INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Bilimsel Düşünme ve Araştırma Metodolojisi' LIMIT 1), 'detail', 'Bilimsel araştırma sürecinde hipotez aşaması hangi adımdan sonra gelir?', '["Veri toplama","Gözlem ve problem tanımlama","Sonuç raporlama","Literatür taraması"]', 1, 'Hipotez, gözlem ve problemin tanımlanmasının ardından oluşturulan açıklayıcı bir önerme olarak gelir.', 4, 5),
((SELECT id FROM text_library WHERE title = 'Bilimsel Düşünme ve Araştırma Metodolojisi' LIMIT 1), 'detail', 'Kontrol grubu kullanmanın temel amacı nedir?', '["Deney süresini kısaltmak","Bağımsız değişkenin etkisini izole etmek","Örneklem büyüklüğünü artırmak","Araştırma maliyetini düşürmek"]', 1, 'Kontrol grubu, bağımsız değişkenin etkisini diğer faktörlerden ayırt etmek için kullanılır.', 4, 6),
((SELECT id FROM text_library WHERE title = 'Bilimsel Düşünme ve Araştırma Metodolojisi' LIMIT 1), 'inference', 'Bir araştırmacı sonuçlarını yalnızca kendi grubuna genellemek yerine farklı kültürel bağlamlarda test ediyorsa bu hangi ilkeye uygun davranmaktadır?', '["İç geçerlilik","Dış geçerlilik","Güvenilirlik","Nesnellik"]', 1, 'Dış geçerlilik, bulguların farklı bağlamlara ve gruplara aktarılabilirliğini ifade eder.', 4, 7),
((SELECT id FROM text_library WHERE title = 'Bilimsel Düşünme ve Araştırma Metodolojisi' LIMIT 1), 'vocabulary', 'Metinde geçen "tümevarım" kavramı en doğru şekilde nasıl açıklanır?', '["Genelden özele ulaşma yöntemi","Özelden genele ulaşma yöntemi","Deneysel veri toplama süreci","Hipotez test etme aşaması"]', 1, 'Tümevarım, özelden genele giden bir akıl yürütme biçimidir; gözlemlerden genel ilkelere ulaşılır.', 4, 8),
((SELECT id FROM text_library WHERE title = 'Bilimsel Düşünme ve Araştırma Metodolojisi' LIMIT 1), 'tone', 'Metnin genel üslubu aşağıdakilerden hangisiyle en doğru biçimde tanımlanır?', '["Eleştirel ve polemikçi","Açıklayıcı ve nesnel","Öznel ve duygusal","Betimleyici ve şiirsel"]', 1, 'Bilimsel metodoloji metinleri genellikle tarafsız, açıklayıcı ve nesnel bir dil kullanır.', 4, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Küresel İklim Değişikliği' LIMIT 1), 'detail', 'Antropojenik iklim değişikliği kavramı neyi ifade eder?', '["Doğal iklim döngülerini","İnsan faaliyetlerinden kaynaklanan iklim değişikliğini","Güneş aktivitesindeki dalgalanmaları","Volkanik patlamalar sonucu oluşan iklim değişikliklerini"]', 1, 'Antropojenik kelimesi "insan kaynaklı" anlamına gelir; bu bağlamda sanayi ve yakıt kullanımının iklime etkisini ifade eder.', 4, 5),
((SELECT id FROM text_library WHERE title = 'Küresel İklim Değişikliği' LIMIT 1), 'detail', 'Sera etkisinin artmasında en büyük paya sahip gaz hangisidir?', '["Metan (CH₄)","Azot dioksit (NO₂)","Karbondioksit (CO₂)","Su buharı (H₂O)"]', 2, 'CO₂, fosil yakıt kullanımı nedeniyle sera etkisinin artışında birincil sorumlu gazdır.', 4, 6),
((SELECT id FROM text_library WHERE title = 'Küresel İklim Değişikliği' LIMIT 1), 'inference', 'İklim değişikliğiyle mücadelede gelişmekte olan ülkelerin katkısı sınırlı tutulursa bu durum hangi sonucu doğurabilir?', '["Küresel sıcaklık hedefleri daha kolay tutturulur","Emisyon azaltımı yetersiz kalır ve hedefler tutturulamaz","Gelişmiş ülkelerin yükü tamamen kalkar","Teknoloji transferi hızlanır"]', 1, 'Tüm ülkelerin katılımı olmadan emisyon azaltım hedeflerine ulaşmak mümkün değildir.', 4, 7),
((SELECT id FROM text_library WHERE title = 'Küresel İklim Değişikliği' LIMIT 1), 'vocabulary', 'Metinde geçen "karbon ayak izi" kavramı ne anlama gelir?', '["Bir ülkenin karbon rezervleri","Bir faaliyetin doğrudan ve dolaylı sera gazı salınımı toplamı","Atmosferdeki toplam CO₂ miktarı","Ormanların CO₂ emme kapasitesi"]', 1, 'Karbon ayak izi, bir birey, kurum veya faaliyetin neden olduğu toplam sera gazı miktarını ifade eder.', 4, 8),
((SELECT id FROM text_library WHERE title = 'Küresel İklim Değişikliği' LIMIT 1), 'tone', 'Metnin iklim değişikliğine yaklaşımı nasıl nitelendirilebilir?', '["Umursamaz ve tarafsız","Endişeli ve çözüm odaklı","İyimser ve kutlayıcı","Siyasi ve partizan"]', 1, 'Metin, iklim değişikliğinin ciddiyetini vurgularken olası çözüm yollarına da dikkat çeker.', 4, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Dil Edinimi ve Evrimsel Kökenler' LIMIT 1), 'detail', 'Chomsky''nin "evrensel dil bilgisi" teorisi ne öngörür?', '["Tüm dillerin aynı kelime dağarcığına sahip olduğunu","İnsanın dilin yapısal kurallarını öğrenmeye doğuştan yatkın olduğunu","Dilin yalnızca taklit yoluyla öğrenildiğini","Dil ediniminin yetişkinlikte tamamlandığını"]', 1, 'Chomsky, insanların dilbilgisel yapıları edinmeye önceden programlanmış zihinsel mekanizmalarla doğduğunu savunur.', 4, 5),
((SELECT id FROM text_library WHERE title = 'Dil Edinimi ve Evrimsel Kökenler' LIMIT 1), 'detail', 'Kritik dönem hipotezine göre dil edinimi hangi dönemde en verimlidir?', '["0-2 yaş","3-12 yaş","13-18 yaş","Yetişkinlik dönemi"]', 1, 'Kritik dönem hipotezi, dil ediniminin erken çocukluk yıllarında (yaklaşık 3-12 yaş) en hızlı ve kalıcı olduğunu öne sürer.', 4, 6),
((SELECT id FROM text_library WHERE title = 'Dil Edinimi ve Evrimsel Kökenler' LIMIT 1), 'inference', 'İkinci dili erken yaşta öğrenen bireylerin aksansız konuşabilmesi hangi bulguyu destekler?', '["Dilin tamamen sosyal öğrenmeyle kazanıldığını","Beynin dil işleme bölgelerinin erken yaşta esnekliğini koruduğunu","Birden fazla dil öğrenmenin zeka düşürdüğünü","Anadilin ikinci dili engellediğini"]', 1, 'Erken yaş ikinci dil edinimi, beynin nöroplastisitesinin yüksek olduğu dönemde gerçekleşir ve aksansız konuşmaya imkân tanır.', 4, 7),
((SELECT id FROM text_library WHERE title = 'Dil Edinimi ve Evrimsel Kökenler' LIMIT 1), 'vocabulary', '"Fonem" terimi metinde nasıl kullanılmaktadır?', '["Bir dilin temel yazım birimi","Bir dilde anlam ayırt edici en küçük ses birimi","Cümle oluşturma kuralları bütünü","Dil öğrenme yöntemi"]', 1, 'Fonem, bir dilde anlam farklılığı yaratan en küçük ses birimidir.', 4, 8),
((SELECT id FROM text_library WHERE title = 'Dil Edinimi ve Evrimsel Kökenler' LIMIT 1), 'tone', 'Yazar dil ediniminin evrimsel kökenlerini ele alırken nasıl bir tutum sergiler?', '["Kesin yargılar veren dogmatik","Farklı görüşleri karşılaştıran analitik","Tarihsel anlatıya dayanan kronik","Duygusal ve kişisel"]', 1, 'Yazar, evrimsel ve bilişsel yaklaşımları karşılaştırarak analitik bir tutum sergiler.', 4, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Ekonomik Büyüme Teorileri' LIMIT 1), 'detail', 'Neo-klasik büyüme modelinde uzun dönemde büyümeyi belirleyen temel unsur nedir?', '["Sermaye birikimi","Teknolojik ilerleme","İşgücü artışı","Dış ticaret dengesi"]', 1, 'Solow modeline göre uzun dönemde sürdürülebilir büyümeyi sağlayan asıl unsur teknolojik ilerlemedir.', 4, 5),
((SELECT id FROM text_library WHERE title = 'Ekonomik Büyüme Teorileri' LIMIT 1), 'detail', 'İçsel büyüme teorileri neo-klasik modelden hangi noktada ayrılır?', '["Sermayenin azalan getiri yasasını reddederek","İşgücünü dışsal kabul ederek","Teknolojik ilerlemeyi eksojen sayarak","Tasarruf oranını sabit tutarak"]', 0, 'İçsel büyüme teorileri, bilgi ve insan sermayesinin birikmesiyle azalan getirilerin önüne geçilebileceğini savunur.', 4, 6),
((SELECT id FROM text_library WHERE title = 'Ekonomik Büyüme Teorileri' LIMIT 1), 'inference', 'Ar-Ge harcamalarına vergi teşviki sağlayan bir hükümet politikası hangi büyüme teorisiyle daha uyumludur?', '["Neo-klasik Solow modeli","İçsel büyüme teorisi","Dengeli büyüme teorisi","Mutlak yakınsama hipotezi"]', 1, 'İçsel büyüme teorisi, Ar-Ge ve yeniliğin büyümeyi içsel olarak sürüklediğini savunduğundan bu politikayla uyumludur.', 4, 7),
((SELECT id FROM text_library WHERE title = 'Ekonomik Büyüme Teorileri' LIMIT 1), 'vocabulary', 'Metinde geçen "yakınsama hipotezi" ne anlama gelir?', '["Zengin ülkelerin daha hızlı büyüdüğü iddiası","Fakir ülkelerin zamanla zengin ülkelere yetişeceği öngörüsü","Tüm ekonomilerin aynı büyüme hızına ulaşmasının imkânsızlığı","Gelir eşitsizliğinin artacağı tahmini"]', 1, 'Yakınsama hipotezi, düşük gelirli ülkelerin sermayenin azalan getirileri nedeniyle daha hızlı büyüyerek zengin ülkelere yakınsayacağını öngörür.', 4, 8),
((SELECT id FROM text_library WHERE title = 'Ekonomik Büyüme Teorileri' LIMIT 1), 'tone', 'Yazar büyüme teorilerini aktarırken hangi tutumu benimser?', '["Belirli bir teoriye açıkça taraf olan savunucu","Teorileri nesnel biçimde karşılaştıran akademik","Büyüme politikalarını eleştiren muhalif","Veri odaklı ampirik"]', 1, 'Metin, farklı teorileri ön yargısız biçimde açıklayan akademik bir üslupla yazılmıştır.', 4, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Felsefede Bilgi Kuramı (Epistemoloji)' LIMIT 1), 'detail', 'Descartes''ın "cogito ergo sum" ifadesi hangi epistemolojik soruya yanıt arar?', '["Ahlaki bilginin kaynağı nedir?","Kesin olarak bilinenin temeli nedir?","Tanrı''nın varlığı kanıtlanabilir mi?","Bilim nasıl ilerler?"]', 1, 'Descartes, şüpheye dayanarak tüm bilgisini sorguladıktan sonra düşünen bir varlık olarak kendisinin var olduğundan emin olabileceğini öne sürer.', 4, 5),
((SELECT id FROM text_library WHERE title = 'Felsefede Bilgi Kuramı (Epistemoloji)' LIMIT 1), 'detail', 'Ampirizm ile rasyonalizm arasındaki temel ayrım nedir?', '["Ahlak ve siyaset felsefesi arasındaki fark","Bilginin duyumlardan mı yoksa akıldan mı geldiği tartışması","Madde ve ruh ikiliği","Özgür irade ve determinizm çatışması"]', 1, 'Ampirizm bilginin duyumlardan, rasyonalizm ise a priori akıl yürütmeden geldiğini savunur.', 4, 6),
((SELECT id FROM text_library WHERE title = 'Felsefede Bilgi Kuramı (Epistemoloji)' LIMIT 1), 'inference', 'Kant''ın "saf aklın eleştirisi" ampirizm ile rasyonalizmi sentezlemeye çalışıyorsa bu girişim hangi sorunu çözmeyi hedefler?', '["Her iki akımın ahlak anlayışlarındaki çelişkiyi","Deneyimin tek başına evrensel zorunlu bilgi sağlayamamasını ve aklın tek başına gerçekliği bilemeyişini","Tanrı''nın varlığına ilişkin kanıt eksikliğini","Dil ile düşünce arasındaki uçurumu"]', 1, 'Kant, deneyim olmadan aklın boş, akıl olmadan deneyimin kör olduğunu söyleyerek ikisini sentezler.', 4, 7),
((SELECT id FROM text_library WHERE title = 'Felsefede Bilgi Kuramı (Epistemoloji)' LIMIT 1), 'vocabulary', 'Metinde geçen "a priori" terimi nasıl tanımlanabilir?', '["Deneyle kazanılan bilgi","Deneyden bağımsız, salt akla dayanan bilgi","Tarihsel belgelerden elde edilen bilgi","Gözlemle doğrulanan bilgi"]', 1, 'A priori, deneyden önce gelen ve deneyden bağımsız olarak aklın kendi içinden ürettiği bilgiyi ifade eder.', 4, 8),
((SELECT id FROM text_library WHERE title = 'Felsefede Bilgi Kuramı (Epistemoloji)' LIMIT 1), 'tone', 'Metnin felsefi meseleleri ele alış biçimi nasıl tanımlanabilir?', '["Polemikçi ve tartışmacı","Sistematik ve sorgulayıcı","Mitolojik ve metaforik","Tarihsel ve kronolojik"]', 1, 'Epistemoloji metinleri kavramları sistematik biçimde açıklar ve temel soruları tartışır.', 4, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'İstatistiksel Analizde Temel Kavramlar' LIMIT 1), 'detail', 'Standart sapma neyi ölçer?', '["Veri setindeki en yüksek değeri","Verilerin ortalamadan ne kadar uzaklaştığını","İki değişken arasındaki ilişkiyi","Örneklemin anakütle içindeki oranını"]', 1, 'Standart sapma, verilerin ortalama etrafındaki yayılımını ölçen bir dağılım ölçüsüdür.', 4, 5),
((SELECT id FROM text_library WHERE title = 'İstatistiksel Analizde Temel Kavramlar' LIMIT 1), 'detail', 'Tip I hata (α hatası) istatistiksel hipotez testinde ne anlama gelir?', '["Yanlış bir hipotezi kabul etmek","Doğru olan sıfır hipotezini reddetmek","Örneklemi yanlış seçmek","Veriyi yanlış kodlamak"]', 1, 'Tip I hata, gerçekte doğru olan H₀ hipotezinin yanlışlıkla reddedilmesidir; yanlış pozitif olarak da bilinir.', 4, 6),
((SELECT id FROM text_library WHERE title = 'İstatistiksel Analizde Temel Kavramlar' LIMIT 1), 'inference', 'p-değeri 0,03 bulunan bir test sonucundan ne sonuç çıkarılabilir?', '["Etki büyüklüğü büyüktür","Anlamlılık düzeyi 0,05 kabul edilirse sıfır hipotezi reddedilebilir","Örneklem yeterince büyük değildir","Sonuç kesinlikle gerçek dünyada önemlidir"]', 1, 'p < 0,05 olduğundan sıfır hipotezi reddedilir; ancak istatistiksel anlamlılık pratik önemi garanti etmez.', 4, 7),
((SELECT id FROM text_library WHERE title = 'İstatistiksel Analizde Temel Kavramlar' LIMIT 1), 'vocabulary', '"Korelasyon" kavramı istatistikte ne anlama gelir?', '["Bir değişkenin diğerini nedensel olarak etkilemesi","İki değişken arasındaki doğrusal ilişkinin gücü ve yönü","Verilerin normal dağılıma uygunluğu","Örneklemdeki aykırı değerlerin sayısı"]', 1, 'Korelasyon, iki değişken arasındaki ilişkinin gücünü ve yönünü ölçer; nedensellik anlamına gelmez.', 4, 8),
((SELECT id FROM text_library WHERE title = 'İstatistiksel Analizde Temel Kavramlar' LIMIT 1), 'tone', 'Metnin istatistik konusunu ele alış üslubu nasıl tanımlanır?', '["Öğretici ve teknik","Eleştirel ve polemikçi","Kişisel ve anekdotik","Edebi ve mecazlı"]', 0, 'İstatistik metodolojisi metinleri, teknik kavramları açık ve öğretici bir dille aktarır.', 4, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Nörobilim ve Bilinç' LIMIT 1), 'detail', 'Nöroplastisite kavramı beyin için ne ifade eder?', '["Beynin sabit ve değişmez yapısı","Beynin deneyim ve öğrenmeye bağlı olarak yapısal değişim gösterme kapasitesi","Beynin farklı bireyler arasındaki boyut farklılıkları","Nöronların elektrik iletim hızı"]', 1, 'Nöroplastisite, beynin yeni sinaptik bağlantılar kurarak kendini yeniden düzenleyebilme yeteneğidir.', 4, 5),
((SELECT id FROM text_library WHERE title = 'Nörobilim ve Bilinç' LIMIT 1), 'detail', 'Bilinç araştırmalarında "zor problem" olarak adlandırılan kavram nedir?', '["Beyin hasarının davranışa etkisini ölçmek","Öznel deneyimin (qualia) nöral süreçlerle nasıl ilişkilendiğini açıklamak","Hafıza kayıplarının nedenlerini bulmak","Uyku düzeninin beyne etkilerini saptamak"]', 1, 'Zor problem, öznel deneyim (qualia) ile fiziksel beyin süreçleri arasındaki açıklanamayan boşluğu ifade eder.', 4, 6),
((SELECT id FROM text_library WHERE title = 'Nörobilim ve Bilinç' LIMIT 1), 'inference', 'Beyin görüntüleme çalışmaları bilinç araştırmalarında kullanılırken hangi sınırlılık göz önünde bulundurulmalıdır?', '["Görüntüleme teknolojisinin pahalı olması","Nöral aktivitenin öznel deneyimi tam olarak yansıtmayabileceği","Deneylerin çok uzun sürmesi","Katılımcı sayısının yetersiz kalması"]', 1, 'Beyin aktivasyonu gözlemlenebilir; ancak öznel deneyimin ne olduğu hâlâ açıklanamaz; korelasyon nedenselliği kanıtlamaz.', 4, 7),
((SELECT id FROM text_library WHERE title = 'Nörobilim ve Bilinç' LIMIT 1), 'vocabulary', 'Metinde geçen "sinaps" terimi ne anlama gelir?', '["Beyin lobları arasındaki sınır","Nöronlar arasındaki kimyasal iletişim noktası","Beyin omurilik sıvısının üretildiği alan","Nöronun çekirdeği"]', 1, 'Sinaps, iki nöron arasında nörotransmitterlerin iletildiği bağlantı noktasıdır.', 4, 8),
((SELECT id FROM text_library WHERE title = 'Nörobilim ve Bilinç' LIMIT 1), 'tone', 'Yazar bilinç konusunu ele alırken nasıl bir tutum sergiler?', '["Kesin yanıtlar sunan otoriter","Belirsizliği kabul eden ve sorgulayan araştırmacı","Bilimi reddeden spiritüalist","Sadece klinik verilere odaklanan"]', 1, 'Bilinç araştırmaları henüz yanıtsız sorular içerdiğinden metin, belirsizliği dürüstçe kabul eden bir üslup taşır.', 4, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Psikolojide Bilişsel Süreçler' LIMIT 1), 'detail', 'Çalışma belleği (working memory) uzun dönem bellekten nasıl ayrılır?', '["Duygusal anıları depolaması","Sınırlı kapasite ve kısa süreli aktif bilgi işleme alanı olması","Yalnızca sözel bilgileri işlemesi","Bilinçdışı süreçleri yönetmesi"]', 1, 'Çalışma belleği, anlık düşünme ve problem çözme için sınırlı kapasiteli geçici bir depolama alanıdır.', 4, 5),
((SELECT id FROM text_library WHERE title = 'Psikolojide Bilişsel Süreçler' LIMIT 1), 'detail', 'Bilişsel önyargılar karar verme süreçlerini nasıl etkiler?', '["Her zaman daha iyi kararlar alınmasını sağlar","Mantık dışı ama tahmin edilebilir hatalar yaratır","Yalnızca düşük zekâlı bireyleri etkiler","Duygu ve düşünceyi birbirinden ayırır"]', 1, 'Bilişsel önyargılar, sistematik ve öngörülebilir düşünce hatalarına yol açar; zekâ düzeyinden bağımsızdır.', 4, 6),
((SELECT id FROM text_library WHERE title = 'Psikolojide Bilişsel Süreçler' LIMIT 1), 'inference', 'Şema teorisine göre yeni bilgileri mevcut zihinsel şemalarla bütünleştirmekte zorlanan bir öğrenci için hangi öğretim stratejisi daha etkilidir?', '["Ezberleme odaklı tekrar","Yeni bilgiyi var olan bilgiye köprü kurarak sunma","Bilgiyi görsel olmadan sözlü aktarma","Sınav baskısıyla motivasyonu artırma"]', 1, 'Şema teorisi, yeni bilginin mevcut zihinsel yapılara bağlanmasıyla daha iyi öğrenildiğini öngörür.', 4, 7),
((SELECT id FROM text_library WHERE title = 'Psikolojide Bilişsel Süreçler' LIMIT 1), 'vocabulary', '"Bilişsel yük" kavramı ne anlama gelir?', '["Hafızanın toplam kapasitesi","Çalışma belleğine tek seferde yüklenen bilgi miktarı","Öğrenme güçlüğünün IQ üzerindeki etkisi","Dikkatin günlük tüketimi"]', 1, 'Bilişsel yük, çalışma belleğinin işlemek zorunda kaldığı bilgi miktarını ifade eder; aşırı yük öğrenmeyi engeller.', 4, 8),
((SELECT id FROM text_library WHERE title = 'Psikolojide Bilişsel Süreçler' LIMIT 1), 'tone', 'Yazar bilişsel süreçleri anlatırken hangi yaklaşımı benimser?', '["Felsefi ve soyut","Ampirik bulgulara dayanan açıklayıcı","Klinik vaka odaklı","Popüler psikoloji tarzında kişisel"]', 1, 'Bilişsel psikoloji metinleri araştırma bulgularına dayanarak kavramları açıklayıcı bir dille aktarır.', 4, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Sosyolojide Kimlik ve Kültür' LIMIT 1), 'detail', 'Sosyal kimlik teorisine göre bireyler hangi temel mekanizma aracılığıyla kimliklerini inşa eder?', '["Biyolojik programlama","Grup üyeliği ve sosyal karşılaştırma","Ekonomik sınıf konumu","Bireysel başarılar"]', 1, 'Tajfel''in sosyal kimlik teorisi, bireylerin grup üyelikleri üzerinden kendilerini tanımladığını ve diğer gruplarla karşılaştırdığını öne sürer.', 4, 5),
((SELECT id FROM text_library WHERE title = 'Sosyolojide Kimlik ve Kültür' LIMIT 1), 'detail', 'Kültürel asimilasyon ve kültürel entegrasyon kavramları arasındaki temel fark nedir?', '["İkisi arasında hiçbir fark yoktur","Asimilasyon özgün kimliği eritirken entegrasyon kendi kimliğini koruyarak uyumu sağlar","Entegrasyon yalnızca ekonomik boyutludur","Asimilasyon yalnızca dil öğrenmeyi kapsar"]', 1, 'Asimilasyon, göçmen kültürünün ev sahibi kültürde erimesidir; entegrasyon ise iki kültürün bir arada var olmasıdır.', 4, 6),
((SELECT id FROM text_library WHERE title = 'Sosyolojide Kimlik ve Kültür' LIMIT 1), 'inference', 'Küreselleşme sürecinde yerel kültürlerin kimliklerini korumakta güçlük çektiği gözlemleniyorsa bu hangi sosyolojik kaygıyı yansıtır?', '["Ekonomik milliyetçilik","Kültürel homojenleşme ve çeşitliliğin azalması","Demografik gerileme","Teknoloji okuryazarlığı açığı"]', 1, 'Küreselleşmenin kültürel boyutu, baskın kültürlerin yerel kimlik ve gelenekleri aşındırması tehlikesini beraberinde getirir.', 4, 7),
((SELECT id FROM text_library WHERE title = 'Sosyolojide Kimlik ve Kültür' LIMIT 1), 'vocabulary', 'Metinde geçen "hegemonya" kavramı sosyoloji bağlamında ne anlama gelir?', '["Askeri üstünlük","Bir grubun kültürel, ideolojik veya siyasi alanlarda baskın olma durumu","Demografik çoğunluk","Ekonomik tekel"]', 1, 'Gramsci''nin hegemonya kavramı, egemen sınıfın değer ve normlarını toplumun tamamına kabul ettirme sürecini ifade eder.', 4, 8),
((SELECT id FROM text_library WHERE title = 'Sosyolojide Kimlik ve Kültür' LIMIT 1), 'tone', 'Yazar kimlik ve kültür konusunu ele alırken nasıl bir üslup kullanır?', '["Milliyetçi ve savunmacı","Eleştirel ve analitik","Nostaljik ve duygusal","Biyografik ve kişisel"]', 1, 'Sosyoloji metinleri toplumsal olguları eleştirel bir gözle analiz eden akademik bir dil kullanır.', 4, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Yapay Zeka ve Etik Sorunlar' LIMIT 1), 'detail', 'Algoritmik önyargı (algorithmic bias) kavramı ne anlama gelir?', '["Algoritmaların kasıtlı olarak yanlış sonuç üretmesi","Eğitim verilerindeki önyargıların algoritmaya yansıyarak sistematik hatalara yol açması","Yapay zekânın insan kararlarına her zaman üstün gelmesi","Programlama dilindeki hataların yol açtığı teknik sorunlar"]', 1, 'Algoritmik önyargı, tarihsel verilerdeki eşitsizliklerin makine öğrenmesi modellerine aktarılmasıyla oluşur.', 4, 5),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka ve Etik Sorunlar' LIMIT 1), 'detail', 'Yapay zekânın şeffaflık sorunu neyi ifade eder?', '["Yapay zekânın internete bağlı olması","Karar alma süreçlerinin anlaşılır ve denetlenebilir olmaması","Verilerin bulutta saklanması","Yapay zekânın maliyetinin yüksekliği"]', 1, 'Kara kutu modelleri, kararlarının gerekçesini açıklayamadığından hesap verebilirlik sorunu doğurur.', 4, 6),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka ve Etik Sorunlar' LIMIT 1), 'inference', 'Yapay zekânın işe alım süreçlerinde kullanılması tarihsel olarak erkeklerin yoğun olduğu rollere daha fazla erkek aday seçiyorsa bu durumda en acil gereken müdahale nedir?', '["Yapay zekâyı işe alımdan tamamen kaldırmak","Eğitim veri setlerini çeşitlendirmek ve çıktıları denetlemek","Daha güçlü bilgisayarlar kullanmak","Daha fazla veri toplamak"]', 1, 'Önyargılı çıktıyı gidermek için önce eğitim verilerini dengeli hâle getirmek ve çıktıları düzenli olarak denetlemek gerekir.', 4, 7),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka ve Etik Sorunlar' LIMIT 1), 'vocabulary', '"Özerk sistem" kavramı yapay zekâ bağlamında ne anlama gelir?', '["İnternetle bağlantısı olmayan sistem","İnsan müdahalesi olmaksızın kendi kararlarını alabilen sistem","Açık kaynaklı yazılım altyapısı","Yalnızca metin işleyen yapay zekâ"]', 1, 'Özerk sistem, belirlenen hedefler doğrultusunda insan onayı gerekmeksizin bağımsız kararlar alabilen yapay zekâ sistemidir.', 4, 8),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka ve Etik Sorunlar' LIMIT 1), 'tone', 'Yazar yapay zekâ etiğini ele alırken hangi tutumu benimser?', '["Teknolojiye körü körüne hayranlık duyan","Riskleri ve fırsatları dengeli biçimde değerlendiren eleştirel","Teknolojiyi tamamen reddeden karşıcı","Yalnızca ekonomik kâra odaklanan"]', 1, 'Metin, yapay zekânın potansiyelini kabul ederken etik riskleri de ciddiye alan dengeli bir yaklaşım sergiler.', 4, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Kuantum Fiziğinin Sırları' LIMIT 1), 'detail', 'Çift yarık deneyi kuantum mekaniğinde hangi ilkeyi göstermektedir?', '["Işığın yalnızca dalga özelliği taşıdığını","Işık ve maddenin hem dalga hem de parçacık özelliği gösterdiğini","Fotonların kütlesi olduğunu","Elektronların daima sabit yörüngede hareket ettiğini"]', 1, 'Çift yarık deneyi, kuantum varlıklarının gözlem yapılana kadar hem dalga hem parçacık davranışı sergilediğini ortaya koyar.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Kuantum Fiziğinin Sırları' LIMIT 1), 'detail', 'Heisenberg''in belirsizlik ilkesi neyi öngörür?', '["Bir parçacığın konumu ve momentumu aynı anda kesin olarak bilinemez","Tüm parçacıkların kütlesi belirsizdir","Kuantum hesaplamalarının her zaman yaklaşık olduğunu","Fotonların hızının ölçülemeyeceğini"]', 0, 'Belirsizlik ilkesi, konum ve momentum gibi eşlenik değişkenlerin aynı anda hassas biçimde ölçülememesini öngörür.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Kuantum Fiziğinin Sırları' LIMIT 1), 'inference', 'Kuantum dolanıklığı iki parçacık arasındaki anlık korelasyonu açıklıyorsa bu durum klasik fizik için neden sorun oluşturur?', '["Klasik fizik enerji korunumunu kabul etmediğinden","Klasik fizik bilginin ışık hızından hızlı aktarılamayacağını öngördüğünden","Klasik fizik parçacıkları tanımayı reddeder","Klasik fizikte dalga denklemi kullanılmadığından"]', 1, 'Klasik fizikte bilgi ışık hızından hızlı gidemez; ancak dolanık parçacıklar anlık korelasyon gösterir; bu çelişki tartışma konusudur.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Kuantum Fiziğinin Sırları' LIMIT 1), 'vocabulary', 'Metinde geçen "süperpozisyon" kavramı ne anlama gelir?', '["Parçacıkların birbirini itmesi","Kuantum sisteminin aynı anda birden fazla durumda bulunması","Atomların katmanlı yapısı","Işığın renklerinin üst üste gelmesi"]', 1, 'Süperpozisyon, bir kuantum sisteminin ölçüm yapılana kadar olası tüm durumları aynı anda var etmesidir.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Kuantum Fiziğinin Sırları' LIMIT 1), 'tone', 'Metin kuantum fiziğini okuyucuya nasıl bir dille aktarır?', '["Ağır matematiksel formüller içeren uzmana yönelik","Merak uyandırıcı ve anlaşılır popüler bilim dili","Eleştirel ve bilim karşıtı","Tamamen felsefi ve soyut"]', 1, 'Popüler bilim metinleri karmaşık kavramları geniş okuyucu kitlesine merak uyandıran bir dille aktarır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Yeşil Enerji ve Sürdürülebilir Gelecek' LIMIT 1), 'detail', 'Güneş enerjisi sistemlerinde "fotovoltaik" kavramı neyi tanımlar?', '["Güneş ışığını ısıya dönüştürme","Güneş ışığını doğrudan elektriğe dönüştürme","Rüzgâr türbinlerinin çalışma prensibi","Biyokütlenin yakılması"]', 1, 'Fotovoltaik hücreler, yarı iletken malzeme aracılığıyla güneş fotonlarını elektrik akımına doğrudan dönüştürür.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Yeşil Enerji ve Sürdürülebilir Gelecek' LIMIT 1), 'detail', 'Rüzgâr enerjisinin en önemli dezavantajı nedir?', '["Çok fazla CO₂ salması","Depolama güçlüğü ve kesintili üretim","Aşırı su tüketimi","Nükleer atık üretmesi"]', 1, 'Rüzgâr enerjisi, rüzgâr hızına bağlı olarak kesintili üretim yapar; bu da depolama sorununu beraberinde getirir.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Yeşil Enerji ve Sürdürülebilir Gelecek' LIMIT 1), 'inference', 'Yenilenebilir enerji kapasitesi artan ancak şebeke altyapısı eskiyen bir ülke için en öncelikli yatırım alanı hangisi olmalıdır?', '["Yeni nükleer santraller inşa etmek","Akıllı şebeke ve enerji depolama sistemleri","Kömür santrallerini modernize etmek","Enerji ithalatını artırmak"]', 1, 'Yenilenebilir enerjinin verimliliği, güçlü bir iletim ve depolama altyapısı olmadan tam olarak kullanılamaz.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Yeşil Enerji ve Sürdürülebilir Gelecek' LIMIT 1), 'vocabulary', '"Karbon nötr" kavramı ne anlama gelir?', '["Hiç karbon salınımı yapmamak","Salınan karbon miktarı ile giderilen karbon miktarının eşit olması","Yalnızca yenilenebilir enerji kullanmak","Fosil yakıt kullanımını sıfırlamak"]', 1, 'Karbon nötrlük, üretilen emisyonların ağaçlandırma veya yakalama yöntemleriyle dengelenmesidir.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Yeşil Enerji ve Sürdürülebilir Gelecek' LIMIT 1), 'tone', 'Metnin yeşil enerjiye yaklaşımı nasıl tanımlanabilir?', '["Şüpheci ve karamsarlık içeren","Umut verici ve çözüm odaklı","Tarafsız ve ilgisiz","Siyasi ve partizan"]', 1, 'Metin, yenilenebilir enerji çözümlerinin olumlu yönlerini vurgulayan iyimser ve çözüm odaklı bir tutum sergiler.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Dilin Evrimi ve Geleceği' LIMIT 1), 'detail', 'Bir dilin "ölü dil" olarak tanımlanabilmesi için hangi koşul gereklidir?', '["Dilin yazı sistemi olmaması","Dili anadil olarak konuşan canlı konuşucunun kalmaması","Dilin resmi statüsünü kaybetmesi","Dilin başka dillere sözcük ödünç vermemesi"]', 1, 'Ölü dil, artık hiçbir topluluk tarafından anadil olarak aktarılmayan dildir; Latince bu gruba girer.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Dilin Evrimi ve Geleceği' LIMIT 1), 'detail', 'Dijital iletişimin dil üzerindeki en belirgin etkilerinden biri nedir?', '["Dillerin sözvarlığını azaltması","Kısaltma, emoji ve yeni sözcüklerin hızla yaygınlaşması","Formal yazı dilinin güçlenmesi","Bölgesel ağızların ortadan kalkması"]', 1, 'Sosyal medya ve anlık mesajlaşma, kısaltmalar ve yeni sözcükler aracılığıyla dili hızla dönüştürmektedir.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Dilin Evrimi ve Geleceği' LIMIT 1), 'inference', 'Yapay zekânın dil çevirisi yapabilmesi, azınlık dillerinin korunmasına nasıl katkı sağlayabilir?', '["Azınlık dillerini gereksiz hâle getirir","Az konuşulan dillerde içerik üretimini ve erişimini kolaylaştırır","Yalnızca büyük diller için faydalıdır","Dil eğitimini imkânsız kılar"]', 1, 'Yapay zekâ destekli çeviri ve içerik üretimi, az konuşulan dillerin dijital platformlarda varlığını sürdürmesini kolaylaştırabilir.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Dilin Evrimi ve Geleceği' LIMIT 1), 'vocabulary', 'Metinde geçen "lingua franca" kavramı ne anlama gelir?', '["Ölmekte olan dil","Farklı anadillere sahip toplulukların iletişim için kullandığı ortak dil","Bir ülkenin resmi dili","Dini törenlerde kullanılan kutsal dil"]', 1, 'Lingua franca, farklı ana dilleri konuşan kişilerin ortak iletişim aracı olarak kullandığı dildir; İngilizce günümüzde bu işlevi görür.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Dilin Evrimi ve Geleceği' LIMIT 1), 'tone', 'Yazar dilin evrimi konusunda hangi duygusal tutumu sergiler?', '["Dil değişimine tamamen karşı olan korumacı","Değişimi kaçınılmaz görerek merakla inceleyen","Dil ölümlerini kutlayan","Geleneksel dil kurallarını katı biçimde savunan"]', 1, 'Metin, dil değişimini kaçınılmaz bir evrim olarak kabul eden ve merakla inceleyen bir perspektif sunar.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Okyanusların Gizemli Derinlikleri' LIMIT 1), 'detail', 'Okyanus derinliklerindeki hidrotermal bacalar hangi açıdan özellikle önem taşır?', '["Deniz ulaşımına yol göstermeleri","Güneş ışığı olmaksızın yaşamı mümkün kılan ekosistemler barındırmaları","Okyanus tabanını ısıtarak iklimi düzenlemeleri","Balıkçılık için zengin alanlar oluşturmaları"]', 1, 'Hidrotermal bacalar, fotosentez yerine kemotrofi ile beslenen canlılara ev sahipliği yaparak bilim dünyasını şaşırtmıştır.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Okyanusların Gizemli Derinlikleri' LIMIT 1), 'detail', 'Okyanus akıntılarının küresel iklim üzerindeki rolü nedir?', '["Okyanusların tuzluluk oranını sabit tutar","Isıyı ekvatordan kutuplara taşıyarak sıcaklık dengesini sağlar","Yağış miktarını doğrudan kontrol eder","Depremlerin yayılmasını engeller"]', 1, 'Termohalin sirkülasyonu, sıcak ve soğuk su kütlelerini taşıyarak küresel sıcaklık dengesine katkıda bulunur.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Okyanusların Gizemli Derinlikleri' LIMIT 1), 'inference', 'Okyanus derinliklerinin yalnızca yüzde beşinin keşfedilmiş olması hangi sonucu doğurur?', '["Okyanusların bilimsel değerinin düşük olduğunu","Keşfedilmemiş türlerin ve kaynakların var olma ihtimalinin yüksek olduğunu","Deniz araştırmalarının gereksiz olduğunu","Okyanusların tamamen haritasının çıkarıldığını"]', 1, 'Büyük ölçüde keşfedilmemiş bir ortamda çok sayıda yeni tür ve kaynak bulunma ihtimali son derece yüksektir.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Okyanusların Gizemli Derinlikleri' LIMIT 1), 'vocabulary', 'Metinde geçen "biyolüminesans" ne anlama gelir?', '["Derin sulardaki yüksek basınç","Canlıların kimyasal tepkimeler aracılığıyla kendi ışığını üretmesi","Okyanustaki fosfor oranı","Derin deniz balıklarının göz yapısı"]', 1, 'Biyolüminesans, organizmaların kimyasal enerjiyi ışığa dönüştürerek ürettiği biyolojik ışıma olayıdır.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Okyanusların Gizemli Derinlikleri' LIMIT 1), 'tone', 'Yazar okyanusları ele alırken hangi tutumu benimser?', '["Tehlikeli ve ürkütücü olarak sunan","Keşfedilmemiş bir dünya olarak merak uyandıran","Ekonomik değerini öne çıkaran","Bilimsel değil edebi bir dil kullanan"]', 1, 'Metin, okyanusları merak uyandırıcı ve keşfe açık bir dünya olarak sunan ilgi çekici bir üslup taşır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Müziğin Psikolojik Etkileri' LIMIT 1), 'detail', 'Müzik dinlemenin beyin üzerindeki anlık etkilerinden biri hangisidir?', '["Kalp atışını her zaman yavaşlatır","Dopamin salgılanmasını tetikleyerek zevk duygusu yaratır","Kortizol seviyesini kalıcı olarak artırır","Dil işleme merkezini devre dışı bırakır"]', 1, 'Keyif alınan müzik, beyin ödül sistemini aktive ederek dopamin salgılanmasına yol açar.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Müziğin Psikolojik Etkileri' LIMIT 1), 'detail', 'Müzik terapisi hangi amaçla kullanılır?', '["Yalnızca fiziksel ağrı tedavisi için","Psikolojik rahatsızlıklar, kronik ağrı ve rehabilitasyon süreçlerinde iyileştirici destek olarak","Sadece çocuklarda dil gelişimi için","İlaç tedavisinin tamamen yerine geçmek için"]', 1, 'Müzik terapisi, depresyon, anksiyete, kronik ağrı ve nörolojik rehabilitasyon dahil pek çok alanda kullanılır.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Müziğin Psikolojik Etkileri' LIMIT 1), 'inference', 'Egzersiz sırasında müzik dinleyen sporcuların daha uzun süre antrenman yapabilmesi hangi mekanizmayla açıklanabilir?', '["Müziğin kas kütlesini artırması","Müziğin yorgunluk algısını azaltarak motivasyonu sürdürmesi","Müziğin oksijen tüketimini düşürmesi","Müziğin nabzı yavaşlatması"]', 1, 'Ritmik müzik, yorgunluk sinyallerini baskılar ve motivasyonu canlı tutar; bu nedenle antrenman süresi uzar.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Müziğin Psikolojik Etkileri' LIMIT 1), 'vocabulary', '"Ritim" kavramı müzik bağlamında nasıl tanımlanır?', '["Sesin frekans yüksekliği","Belirli zaman aralıklarında tekrar eden ses ve sessizlik düzeni","Enstrüman sayısı","Müzikal notaların yazım biçimi"]', 1, 'Ritim, müzikal seslerin zaman içindeki düzenli örüntüsü ve tekrar kalıbıdır.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Müziğin Psikolojik Etkileri' LIMIT 1), 'tone', 'Yazar müziğin psikolojik etkilerini nasıl bir dille ele alır?', '["Müziği sıradan gösteren küçümseyici","Bulguları ön plana çıkaran bilgilendirici ve coşkulu","Yalnızca klasik müziği savunan elitist","Müzik endüstrisini eleştiren"]', 1, 'Metin, bilimsel bulguları ön plana çıkaran ve müziğin gücüne ilgi uyandıran bir ton taşır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türk Mutfağının Zengin Tarihi' LIMIT 1), 'detail', 'Osmanlı saray mutfağının çeşitliliği neyin bir yansımasıdır?', '["Yalnızca Anadolu coğrafyasının tarımsal zenginliği","Geniş bir imparatorluk coğrafyasından gelen farklı kültürel ve mutfak etkilerinin sentezi","Avrupa mutfağından birebir ödünç alınan tarifler","Sanayi devriminin gıda üretimine etkisi"]', 1, 'Osmanlı mutfağı, Anadolu, Orta Asya, Arap, Balkan ve Akdeniz kültürlerinin harmanlanmasıyla zenginleşmiştir.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Türk Mutfağının Zengin Tarihi' LIMIT 1), 'detail', 'Türk mutfağında baharatların tarihsel önemi neyle ilgilidir?', '["Yalnızca lezzet amaçlı kullanımları","İpek Yolu ticareti ve farklı kültürlerle kurulan etkileşim","Modern tarımın baharatları ucuzlatması","Osmanlı döneminde baharat yasağının kalkması"]', 1, 'İpek Yolu, Türk topraklarını önemli bir ticaret güzergâhı hâline getirerek farklı baharatların Türk mutfağına girmesini sağlamıştır.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Türk Mutfağının Zengin Tarihi' LIMIT 1), 'inference', 'Türk mutfağının UNESCO tarafından somut olmayan kültürel miras listesine alınması hangi anlama gelir?', '["Yalnızca belirli yemeklerin korunacağı","Mutfak geleneğinin uluslararası arenada değer gördüğü ve gelecek kuşaklara aktarılması gerektiği","Türkiye''nin en büyük ihracat kaleminin yiyecekler olduğu","Mutfak tariflerinin telif hakkına alındığı"]', 1, 'UNESCO tanınması, bir kültürel pratiğin dünya mirası olarak korunması gerektiğini tescil eder.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Türk Mutfağının Zengin Tarihi' LIMIT 1), 'vocabulary', '"Gastronomi" kavramı ne anlama gelir?', '["Midede gıdanın sindirilmesi","Yemek kültürü, pişirme sanatı ve yiyeceklerle insan kültürü arasındaki ilişkinin incelenmesi","Oruç ve perhiz uygulamaları","Yalnızca restoran yönetimi"]', 1, 'Gastronomi, iyi yemek yeme sanatını ve yiyeceğin kültürel, sosyal boyutlarını inceleyen disiplindir.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Türk Mutfağının Zengin Tarihi' LIMIT 1), 'tone', 'Yazar Türk mutfağını anlatırken nasıl bir tutum sergiler?', '["Eleştirel ve olumsuz","Kültürel zenginliğe hayranlık duyan ve övgü içeren","Nesnel ve duygusuz","Diğer mutfaklarla kıyaslayarak küçümseyen"]', 1, 'Metin, Türk mutfağının tarihsel ve kültürel zenginliğini ön plana çıkaran coşkulu bir anlatı taşır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Meditasyonun Beyne Etkisi' LIMIT 1), 'detail', 'Düzenli meditasyon pratiğinin beyin yapısında gözlemlenen en dikkat çekici değişikliklerden biri nedir?', '["Beyin kütlesinin azalması","Prefrontal kortekste gri madde yoğunluğunun artması","Amigdalanın büyümesi","Dil merkezinin küçülmesi"]', 1, 'Araştırmalar, uzun süreli meditasyon yapanların prefrontal kortekslerinde artan gri madde yoğunluğu gösterdiğini ortaya koymuştur.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Meditasyonun Beyne Etkisi' LIMIT 1), 'detail', 'Mindfulness meditasyonu stres yönetimine nasıl katkı sağlar?', '["Amigdalayı kalıcı olarak devre dışı bırakarak","Kortizol tepki eşiğini yükselterek ve anlık farkındalığı artırarak","Düşünceyi tamamen durdurup zihinsel boşluk yaratarak","Uyku süresini azaltarak enerji tasarrufu yaparak"]', 1, 'Mindfulness, stres tetikleyicilere verilen tepkiyi yeniden çerçeveleyerek kortizol salınımını düzenler.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Meditasyonun Beyne Etkisi' LIMIT 1), 'inference', 'Meditasyon yapan bireylerin karar alma süreçlerinde daha az duygusal tepki vermesi hangi beyin bölgesiyle ilişkilendirilebilir?', '["Serebellum (beyincik)","Prefrontal korteks aktivasyonunun artması ve amigdala aktivasyonunun azalması","Hipokampüsün küçülmesi","Beyin sapının güçlenmesi"]', 1, 'Meditasyon, duygusal tepkileri düzenleyen amigdalayı sakinleştirirken rasyonel karar verme merkezini güçlendirir.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Meditasyonun Beyne Etkisi' LIMIT 1), 'vocabulary', 'Metinde geçen "nöroplastisite" kavramı meditasyon bağlamında ne anlama gelir?', '["Beyin kütlesinin genetik olarak belirlenmesi","Beynin düzenli pratikle yeni bağlantılar kurabilme ve kendini yeniden düzenleme kapasitesi","Meditasyonun yalnızca gençlerde etkili olması","Beynin yaşla birlikte sertleşmesi"]', 1, 'Nöroplastisite, meditasyon gibi pratiklerin beyin yapısını ve işlevini değiştirebileceğini açıklar.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Meditasyonun Beyne Etkisi' LIMIT 1), 'tone', 'Yazar meditasyonun faydalarını anlatırken hangi tutumu benimser?', '["Mistik ve dinî","Bilimsel kanıtlara dayanan nesnel ve bilgilendirici","Abartılı ve reklamcı","Şüpheci ve küçümseyici"]', 1, 'Metin, meditasyonun etkilerini nörobilimsel araştırmalara dayandırarak nesnel bir perspektifle aktarır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Dijital Çağda Mahremiyet' LIMIT 1), 'detail', 'Kişisel verilerin toplanması ve kullanılmasını düzenleyen GDPR hangi coğrafyada uygulanır?', '["Yalnızca ABD''de","Avrupa Birliği ve Avrupa Ekonomik Alanı''nda","Tüm dünyada zorunlu olarak","Yalnızca Asya-Pasifik bölgesinde"]', 1, 'GDPR (Genel Veri Koruma Yönetmeliği), AB ve AEA sınırları içinde kişisel veri işleyen tüm kuruluşlara uygulanır.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Dijital Çağda Mahremiyet' LIMIT 1), 'detail', 'Sosyal medya platformlarının kullanıcı verilerini reklam amaçlı kullanması hangi mahremiyet sorununu doğurur?', '["Verilerin fiziksel olarak çalınması","Kullanıcıların rızaları olmaksızın profillendirilmesi ve hedeflenmesi","İnternet hızının yavaşlaması","Hesap güvenliğinin artması"]', 1, 'Platformlar, davranışsal veri toplar ve bunu kullanıcının farkında olmadığı reklam hedefleme için kullanır.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Dijital Çağda Mahremiyet' LIMIT 1), 'inference', 'Bir şirketin veri ihlali yaşaması durumunda kullanıcıların bilgilendirilmemesi hangi etik ilkeyi çiğner?', '["Kâr maksimizasyonu","Şeffaflık ve hesap verebilirlik","Veri minimizasyonu","Anonimleştirme"]', 1, 'Kullanıcılar verilerinin tehlikeye girdiğini bilme hakkına sahiptir; bu bilginin gizlenmesi şeffaflık ilkesini ihlal eder.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Dijital Çağda Mahremiyet' LIMIT 1), 'vocabulary', '"Veri anonimleştirme" ne anlama gelir?', '["Verilerin tamamen silinmesi","Kişiyi tanımlamaya yarayan bilgilerin kaldırılarak verinin kime ait olduğunun anlaşılamaması","Verilerin şifrelenerek saklanması","Verilerin yalnızca şirket içinde paylaşılması"]', 1, 'Anonimleştirme, kişisel tanımlayıcıları kaldırarak bireyin kimliğini tespit edilemez hâle getirir.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Dijital Çağda Mahremiyet' LIMIT 1), 'tone', 'Yazar dijital mahremiyeti ele alırken hangi tutumu sergiler?', '["Teknolojiyi tamamen reddeden","Bireyin haklarını ön plana alan uyarıcı ve bilinçlendirici","Şirketlerin veri kullanımını destekleyen","Mahremiyeti önemsiz bulan"]', 1, 'Metin, kullanıcıları dijital gizlilik riskleri konusunda bilinçlendiren ve hakları ön plana alan bir perspektif sunar.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Uzay Keşfinin Geleceği' LIMIT 1), 'detail', 'Artemis programının temel hedefi nedir?', '["Mars''a ilk insanlı görev","Ay''a sürdürülebilir insanlı varlık kurarak derin uzay keşiflerine zemin hazırlamak","Uluslararası Uzay İstasyonu''nu genişletmek","Venüs''ü haritalamak"]', 1, 'NASA liderliğindeki Artemis programı, insanların Ay''a geri dönmesini ve kalıcı bir üs kurulmasını hedefler.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Uzay Keşfinin Geleceği' LIMIT 1), 'detail', 'Özel uzay şirketlerinin uzay endüstrisine katkısı nasıl değerlendirilebilir?', '["Uzay keşiflerini yavaşlatmıştır","Maliyetleri düşürerek fırlatma sıklığını artırmış ve rekabeti canlandırmıştır","Yalnızca turizm amaçlı çalışmaktadırlar","Devlet kurumlarının yerini tamamen almıştır"]', 1, 'SpaceX gibi şirketler, yeniden kullanılabilir roketlerle maliyetleri önemli ölçüde düşürerek uzay erişimini demokratikleştirmiştir.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Uzay Keşfinin Geleceği' LIMIT 1), 'inference', 'İnsanlığın Mars''a yerleşmesi senaryosunda en kritik çözülmesi gereken sorun hangisidir?', '["Mars''ın Dünya''ya uzaklığı","Uzun süreli uzay yolculuğunun insan sağlığı üzerindeki etkileri ve Mars''taki kaynak sağlama sorunu","Uzay araçlarının ağırlığı","Uzayda internet bağlantısı"]', 1, 'Radyasyon maruziyeti, kemik kaybı, psikolojik etkiler ve Mars''ta oksijen/su temini en kritik mühendislik ve tıp sorunlarıdır.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Uzay Keşfinin Geleceği' LIMIT 1), 'vocabulary', '"Terraforming" kavramı uzay bağlamında ne anlama gelir?', '["Uzay aracı inşası","Bir gezegenin atmosfer ve yüzey koşullarını insanların yaşayabileceği hâle dönüştürme süreci","Gezegenin haritalanması","Uzayda tarım yapma"]', 1, 'Terraforming, başka bir gezegenin koşullarını Dünya''ya benzer hâle getirerek insan yaşamına uygun kılma sürecidir.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Uzay Keşfinin Geleceği' LIMIT 1), 'tone', 'Metnin uzay keşiflerine yaklaşımı nasıl tanımlanabilir?', '["Karamsar ve imkânsız bulan","İyimser ve ilham verici","Yalnızca ekonomik çıkarları sorgulayan","Bilimsel olmayan spekülatif"]', 1, 'Metin, uzay keşiflerinin geleceğini heyecan verici bir vizyon olarak sunan ilham verici bir üslup taşır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Yapay Zeka Günlük Hayatı Nasıl Değiştiriyor?' LIMIT 1), 'detail', 'Öneri sistemleri (recommendation systems) günlük hayatta en yaygın hangi uygulamalarda kullanılır?', '["Trafik ışığı kontrolü","Müzik, film ve alışveriş platformlarında kişiselleştirilmiş içerik önerileri","Hava durumu tahmini","Banka hesap yönetimi"]', 1, 'Netflix, Spotify ve Amazon gibi platformlar, kullanıcı davranışlarını analiz ederek kişiselleştirilmiş öneriler sunar.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka Günlük Hayatı Nasıl Değiştiriyor?' LIMIT 1), 'detail', 'Yapay zekânın sağlık alanındaki kullanımına ilişkin öne çıkan bir uygulama hangisidir?', '["Hastanelerin temizlik programı","Tıbbi görüntülerde hastalık tespiti ve erken tanı","Ameliyathane ısı kontrolü","Hasta kabulü için sıra yönetimi"]', 1, 'Yapay zekâ, röntgen ve MR gibi görüntülerde insan gözünü aşan hassasiyetle hastalık belirtilerini tespit edebilir.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka Günlük Hayatı Nasıl Değiştiriyor?' LIMIT 1), 'inference', 'Yapay zekânın işgücü piyasasında yarattığı dönüşümden en fazla etkilenecek çalışma alanı hangisidir?', '["Tekrarlayan ve kurallara dayalı görevler yapan meslekler","Empati ve yaratıcılık gerektiren meslekler","El becerisi yoğun zanaatkârlık","Açık hava ve doğa temelli meslekler"]', 0, 'Rutin ve kurallara dayalı görevler en kolay otomatize edilebilir; yaratıcılık ve empati gerektiren alanlar daha geç etkilenir.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka Günlük Hayatı Nasıl Değiştiriyor?' LIMIT 1), 'vocabulary', '"Makine öğrenmesi" kavramı ne anlama gelir?', '["Fabrikadaki otomatik makinelerin çalışması","Bilgisayar sistemlerinin veriden örüntü öğrenerek performansını otomatik iyileştirmesi","İnsanın makine kullanmayı öğrenmesi","Makinelerin birbirini tamir etmesi"]', 1, 'Makine öğrenmesi, algoritmaların veriden öğrenerek tahmin ve karar kalitesini giderek iyileştirmesini sağlar.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka Günlük Hayatı Nasıl Değiştiriyor?' LIMIT 1), 'tone', 'Yazar yapay zekânın günlük hayata etkilerini nasıl bir dille aktarır?', '["Yapay zekâya karşı korkutucu bir uyarı diliyle","Olumlu ve olumsuz yönleri dengeli biçimde aktaran bilgilendirici","Yalnızca olumlu yönlerini öven reklamcı","Teknik jargon ağırlıklı uzman diliyle"]', 1, 'Metin, yapay zekânın günlük hayata etkilerini dengeli ve anlaşılır bir dille aktarır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Anadolu''nun Coğrafi Özellikleri' LIMIT 1), 'detail', 'Anadolu''nun iklim çeşitliliğinin temel nedeni nedir?', '["Nüfus yoğunluğunun yüksek olması","Farklı denizler ve dağ kuşaklarıyla çevrili engebeli yapısı","Sanayi faaliyetlerinin yoğun olması","Akarsuların çok sayıda olması"]', 1, 'Anadolu; Karadeniz, Ege, Akdeniz ve İç Anadolu gibi birbirinden farklı iklim bölgelerine ev sahipliği yapan engebeli bir yarımadadır.', 3, 5),
((SELECT id FROM text_library WHERE title = 'Anadolu''nun Coğrafi Özellikleri' LIMIT 1), 'detail', 'Fay hatları bakımından Anadolu''nun önemi nedir?', '["Anadolu deprem riskinin düşük olduğunu gösterir","Anadolu, Avrasya, Arap ve Afrika plakaları arasında sıkışmış aktif bir deprem kuşağında yer alır","Fay hatları yalnızca Doğu Anadolu''da bulunur","Fay hatları doğal kaynakların göstergesidir"]', 1, 'Türkiye, sismik açıdan aktif olan Alp-Himalaya kuşağında yer aldığından yüksek deprem riski taşır.', 3, 6),
((SELECT id FROM text_library WHERE title = 'Anadolu''nun Coğrafi Özellikleri' LIMIT 1), 'inference', 'Anadolu''nun üç tarafının denizle çevrili olması tarih boyunca hangi avantajı sağlamıştır?', '["İklimi olumsuz etkilemiştir","Ticaret yolları, kültürel etkileşim ve denizcilik açısından stratejik üstünlük sağlamıştır","Savunma açısından dezavantaj oluşturmuştur","Tarım arazilerini azaltmıştır"]', 1, 'Denize kıyısı olan yarımada yapısı, Anadolu''yu ticaret, ulaşım ve kültürel alışveriş açısından tarih boyunca kilit bir konum hâline getirmiştir.', 3, 7),
((SELECT id FROM text_library WHERE title = 'Anadolu''nun Coğrafi Özellikleri' LIMIT 1), 'vocabulary', '"Step" ya da "bozkır" kavramı Anadolu bağlamında ne anlama gelir?', '["Sık ormanlık alan","Az yağış alan, kısa otların kapladığı geniş düzlük","Alçak kıyı ovaları","Sulak arazi"]', 1, 'Bozkır, yarı kurak iklimde görülen, ağaçsız ve kısa çimenlerle kaplı geniş düzlüklerdir; İç Anadolu''nun büyük bölümü bu özelliği taşır.', 3, 8),
((SELECT id FROM text_library WHERE title = 'Anadolu''nun Coğrafi Özellikleri' LIMIT 1), 'tone', 'Metnin Anadolu coğrafyasına yaklaşımı nasıl nitelendirilebilir?', '["Eleştirel ve olumsuz","Tanımlayıcı ve bilgilendirici","Edebi ve şiirsel","Milliyetçi ve abartılı"]', 1, 'Coğrafya metinleri bölgelerin özelliklerini betimleyici ve bilgilendirici bir dille aktarır.', 3, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Dış Politikası' LIMIT 1), 'detail', '"Komşularla sıfır sorun" politikası hangi dönemde ön plana çıkmıştır?', '["1950''ler","2000''lerin başı","1980''ler","1923 Cumhuriyet''in kuruluşu"]', 1, 'Ahmet Davutoğlu''nun mimarı olduğu bu politika 2000''li yılların başında Türkiye''nin komşularıyla ilişkilerini normalleştirmeyi hedefliyordu.', 3, 5),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Dış Politikası' LIMIT 1), 'detail', 'Türkiye''nin NATO üyeliği Türk dış politikasına hangi boyutu katmaktadır?', '["Türkiye''yi yalnızca Batı ile ilişkilendirmektedir","Kolektif savunma güvencesi ve Batı ittifakıyla stratejik bağ","Türkiye''nin Orta Doğu''daki etkisini kısıtlar","NATO üyeliği Türkiye''nin tarafsızlığını zorunlu kılmaktadır"]', 1, 'NATO üyeliği, Türkiye''ye Madde 5 kapsamında kolektif savunma güvencesi ve Batı ittifakıyla stratejik bir bağ sunmaktadır.', 3, 6),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Dış Politikası' LIMIT 1), 'inference', 'Türkiye''nin hem NATO üyesi hem de Rusya ile belirli alanlarda işbirliği yapması hangi dış politika yaklaşımını yansıtır?', '["Tam yansızlık politikası","Çok boyutlu ve pragmatik dış politika anlayışı","Yalnızca Doğu yönelimli politika","Katı ittifak bağlılığı"]', 1, 'Türkiye, jeopolitik konumu gereği farklı güçlerle esnek ve çok boyutlu bir dış politika yürütmektedir.', 3, 7),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Dış Politikası' LIMIT 1), 'vocabulary', '"Diplomatik müzakere" kavramı dış politika bağlamında ne anlama gelir?', '["Askeri müdahale","Devletlerin karşılıklı çıkarları doğrultusunda anlaşmaya varmak için yürüttüğü görüşmeler","Ekonomik yaptırım","Uluslararası mahkemeye başvurma"]', 1, 'Diplomatik müzakere, tarafların çatışma veya anlaşmazlıkları silahlı yöntemlere başvurmaksızın çözdüğü görüşme sürecidir.', 3, 8),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Dış Politikası' LIMIT 1), 'tone', 'Metin Türkiye''nin dış politikasını hangi perspektiften ele alır?', '["Bir tarafı açıkça destekleyen partizan","Farklı dönemleri ve politikaları karşılaştıran analitik","Eleştirel ve muhalif","Yalnızca başarıları öven kutlayıcı"]', 1, 'Türk dış politikasını inceleyen akademik metinler genellikle farklı dönem ve yaklaşımları karşılaştıran analitik bir üslup benimser.', 3, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Ekonomik Kalkınma Süreci' LIMIT 1), 'detail', '1980 sonrası Türkiye''de uygulanan ekonomik politikaların temel yönelimi nedir?', '["Devlet müdahalesini artırmak","İthal ikameci sanayileşme","Dışa açık pazar ekonomisine geçiş ve liberalleşme","Merkezi planlama ekonomisi"]', 2, '24 Ocak 1980 kararları, Türkiye''nin dışa kapalı ekonomiden serbest piyasaya ve ihracat odaklı büyümeye geçişini hızlandırmıştır.', 3, 5),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Ekonomik Kalkınma Süreci' LIMIT 1), 'detail', '2001 krizi sonrası Türkiye''nin ekonomik istikrarı yeniden kazanmasında hangi kurum kritik rol oynamıştır?', '["Devlet Planlama Teşkilatı","IMF destekli güçlü ekonomiye geçiş programı ve bağımsız TCMB","Özel bankalar","Avrupa Birliği fonları"]', 1, '2001 sonrasında Derviş programı ve TCMB''nin bağımsız para politikası, Türkiye''nin enflasyonu düşürüp büyümesini sağlamlaştırmasına yardımcı olmuştur.', 3, 6),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Ekonomik Kalkınma Süreci' LIMIT 1), 'inference', 'Türkiye''nin cari açık sorunu ile enerji ithalatı arasında nasıl bir ilişki vardır?', '["Enerji ithalatı cari açıkla ilgisizdir","Yüksek enerji ithalatı, döviz çıkışını artırarak cari açığa katkıda bulunur","Cari açık yalnızca ihracat eksikliğinden kaynaklanır","Enerji ithalatının azalması cari açığı artırır"]', 1, 'Türkiye enerji ihtiyacının büyük bölümünü ithal ettiğinden enerji faturaları cari açığın önemli bir bileşenini oluşturur.', 3, 7),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Ekonomik Kalkınma Süreci' LIMIT 1), 'vocabulary', '"Enflasyon" kavramı ekonomide ne anlama gelir?', '["Para arzının azalması","Mal ve hizmetlerin genel fiyat düzeyinin sürekli artması","Döviz kurunun değer kazanması","İşsizlik oranının düşmesi"]', 1, 'Enflasyon, ekonomide fiyatlar genel düzeyinin sürekli yükselmesi ve dolayısıyla paranın satın alma gücünün azalmasıdır.', 3, 8),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Ekonomik Kalkınma Süreci' LIMIT 1), 'tone', 'Metin Türkiye''nin ekonomik kalkınma sürecini nasıl ele alır?', '["Yalnızca başarıları öven","Başarı ve sorunları birlikte değerlendiren dengeli analitik","Ekonomik politikaları siyasi eleştiri perspektifinden inceleyen","Veri içermeyen soyut"]', 1, 'İyi bir ekonomik kalkınma analizi, hem elde edilen kazanımları hem de yapısal sorunları dengeli biçimde ele alır.', 3, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'İnsan Hakları ve Türkiye' LIMIT 1), 'detail', 'Avrupa İnsan Hakları Mahkemesi''nin Türkiye aleyhine verdiği kararların hukuki sonucu nedir?', '["Türkiye''nin AB''den çıkarılması","Türkiye''nin kararları uygulamak ve gereken reformları yapmakla yükümlü tutulması","Kararların bağlayıcı olmadığından uygulanmaması","Türkiye''ye askeri yaptırım uygulanması"]', 1, 'AİHM kararları bağlayıcı nitelik taşır; Türkiye bu kararları uygulamak ve gerekli yasal düzenlemeleri yapmakla yükümlüdür.', 3, 5),
((SELECT id FROM text_library WHERE title = 'İnsan Hakları ve Türkiye' LIMIT 1), 'detail', '1982 Anayasası''nda temel hak ve özgürlüklere getirilen sınırlamaların meşruiyet koşulları nelerdir?', '["Sınırlama koşulu yoktur, haklar mutlaktır","Yasayla öngörülmüş olması ve demokratik toplum için zorunlu ve ölçülü olması","Cumhurbaşkanı kararnamesiyle yapılabilir","Yürütme organının takdir yetkisine bırakılmıştır"]', 1, 'Anayasa ve AİHS, temel hakların ancak kanunla, zorunlu durumlarda ve ölçülülük ilkesine uygun biçimde sınırlanabileceğini öngörür.', 3, 6),
((SELECT id FROM text_library WHERE title = 'İnsan Hakları ve Türkiye' LIMIT 1), 'inference', 'İnsan haklarının korunmasında bağımsız yargının rolü neden vazgeçilmezdir?', '["Yargı yalnızca ceza davalarına bakar","Bağımsız yargı, yürütmenin insan hakları ihlallerine karşı bireye başvuru ve tazminat hakkı sağlar","Yargı bağımsızlığı hükümetin etkinliğini azaltır","Bağımsız yargı yalnızca ekonomik davalarda önem taşır"]', 1, 'Bağımsız yargı olmadan devletin kendisi ihlalciye dönüşebilir; bireyler haksız uygulamalara karşı etkili başvuru yolundan yoksun kalır.', 3, 7),
((SELECT id FROM text_library WHERE title = 'İnsan Hakları ve Türkiye' LIMIT 1), 'vocabulary', '"Hukukun üstünlüğü" ilkesi ne anlama gelir?', '["En güçlü devletin yasaları belirlemesi","Devlet dahil tüm kişi ve kurumların hukukun altında olması ve yasalara bağlı bulunması","Yasaların vatandaşlar için değil yöneticiler için geçerli olması","Mahkemelerin her davada hükümeti desteklemesi"]', 1, 'Hukukun üstünlüğü, devlet otoritesinin de yazılı kurallara tabi olduğu ve kimsenin kanunun üstünde olmadığı ilkesidir.', 3, 8),
((SELECT id FROM text_library WHERE title = 'İnsan Hakları ve Türkiye' LIMIT 1), 'tone', 'Metin insan hakları konusunu nasıl bir perspektiften ele alır?', '["Hükümet politikalarını koşulsuz savunan","İnsan haklarının evrensel standartlarını referans alan nesnel değerlendirme","Tamamen eleştirel ve muhalif","Yalnızca iç hukuku esas alan yerel bakış açısı"]', 1, 'Hukuk ve insan hakları metinleri genellikle uluslararası standartları referans alarak nesnel bir değerlendirme sunar.', 3, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Anayasal Düzeni' LIMIT 1), 'detail', '2017 anayasa değişikliğiyle Türkiye''de hükümet sistemi nasıl dönüşmüştür?', '["Parlamenter sistemden başkanlık sistemine geçilmiştir","Başkanlık sisteminden parlamenter sisteme geçilmiştir","Yargı bağımsızlığı güçlendirilmiştir","Yerel yönetimler kaldırılmıştır"]', 0, '2017 referandumuyla kabul edilen değişiklikle Türkiye, yürütme yetkisini cumhurbaşkanlığında toplayan başkanlık hükümet sistemine geçmiştir.', 3, 5),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Anayasal Düzeni' LIMIT 1), 'detail', 'Anayasa Mahkemesi''nin görevleri arasında hangisi yer alır?', '["Yürütme kararnamelerini hazırlamak","Kanunların anayasaya uygunluğunu denetlemek","Devlet bütçesini onaylamak","Bakanları atamak"]', 1, 'Anayasa Mahkemesi, yasama organının çıkardığı kanunları anayasal ilkeler açısından denetler.', 3, 6),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Anayasal Düzeni' LIMIT 1), 'inference', 'Güçler ayrılığı ilkesinin zayıflaması demokratik yönetim için nasıl bir tehlike oluşturur?', '["Yasama hızlanır","Bir organın diğerleri üzerinde denetimsiz güç toplaması ve hesap verebilirliğin azalması","Yargı bağımsızlaşır","Yerel yönetimler güçlenir"]', 1, 'Güçler ayrılığı olmadan tek bir güç odağı denge ve denetim mekanizmalarını devre dışı bırakabilir.', 3, 7),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Anayasal Düzeni' LIMIT 1), 'vocabulary', '"Olağanüstü hal" kavramı anayasa hukukunda ne anlama gelir?', '["Seçim dönemine verilen ad","Tehditlere karşı yürütmenin olağan dönemden daha geniş yetkiler kullandığı istisnai yönetim hâli","Meclisin tatile girdiği dönem","Anayasa değişikliği süreci"]', 1, 'Olağanüstü hal, doğal afet, savaş veya güvenlik tehdidi gibi durumlarda yürütmeye geçici ve genişletilmiş yetkiler tanınan anayasal istisna rejimidir.', 3, 8),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Anayasal Düzeni' LIMIT 1), 'tone', 'Metnin anayasal düzeni ele alış biçimi nasıl nitelendirilebilir?', '["Siyasi parti perspektifinden","Hukuki analiz ve kurumsal yapıyı açıklayan teknik akademik","Anayasayı eleştiren muhalif","Tarihsel kronoloji odaklı"]', 1, 'Anayasa hukuku metinleri kurumsal yapıları, hukuki çerçeveyi ve işleyişi teknik ve akademik bir dille açıklar.', 3, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türkiye''de Demokratikleşme Süreci' LIMIT 1), 'detail', '1950 seçimleri Türkiye''nin siyasi tarihi açısından neden dönüm noktası sayılır?', '["İlk kez cumhurbaşkanı seçildiğinden","Tek parti iktidarından çok partili demokratik sisteme ilk iktidar devri gerçekleştiğinden","NATO''ya üye olunduğundan","Anayasanın yeniden yazıldığından"]', 1, '1950 seçimleriyle CHP''den DP''ye ilk barışçıl iktidar devri yaşanmış, bu durum Türkiye''de çok partili demokrasinin sınanması açısından tarihî önem taşımıştır.', 3, 5),
((SELECT id FROM text_library WHERE title = 'Türkiye''de Demokratikleşme Süreci' LIMIT 1), 'detail', 'Türkiye''de sivil-asker ilişkilerinin demokratikleşmedeki önemi nedir?', '["Askerin siyasete katılımı demokrasiyi güçlendirir","Ordunun sivil denetime tabi kılınması demokratik normların pekişmesi için zorunludur","Askeri müdahaleler her zaman demokratik gelişimi hızlandırmıştır","Sivil-asker ilişkileri anayasal çerçevenin dışında kalır"]', 1, 'Demokratik sistemlerde ordu sivil iradenin denetimine tabi olmalıdır; bu ilkenin yerleşmesi demokratik konsolidasyonun temel ölçütlerinden biridir.', 3, 6),
((SELECT id FROM text_library WHERE title = 'Türkiye''de Demokratikleşme Süreci' LIMIT 1), 'inference', 'Türkiye''nin AB üyelik süreci demokratikleşme politikaları üzerinde nasıl bir etki yaratmıştır?', '["AB süreci demokratikleşme üzerinde etkisiz kalmıştır","AB kriterleri, özellikle 2000''li yıllarda hukuk devleti ve temel haklar alanında reformları teşvik etmiştir","AB süreci Türkiye''yi daha otoriter bir yöne itmiştir","AB yalnızca ekonomik alanda baskı uygulamıştır"]', 1, 'Kopenhag kriterleri çerçevesinde AB üyelik süreci, Türkiye''de yargı, ifade özgürlüğü ve azınlık hakları gibi alanlarda köklü reformlara zemin hazırlamıştır.', 3, 7),
((SELECT id FROM text_library WHERE title = 'Türkiye''de Demokratikleşme Süreci' LIMIT 1), 'vocabulary', '"Sivil toplum" kavramı demokratikleşme bağlamında ne ifade eder?', '["Resmi devlet kurumları","Devletten bağımsız olarak faaliyet gösteren sivil örgütlenmeler ve gönüllü kuruluşlar","Ordu ve polis teşkilatı","Siyasi partiler"]', 1, 'Sivil toplum, devlet otoritesinden bağımsız biçimde örgütlenen, demokratik katılımı güçlendiren gönüllü kuruluşlar ve ağları ifade eder.', 3, 8),
((SELECT id FROM text_library WHERE title = 'Türkiye''de Demokratikleşme Süreci' LIMIT 1), 'tone', 'Metnin demokratikleşme sürecini ele alış biçimi nasıl tanımlanır?', '["Yalnızca başarıları öven","Reformları ve engelleri birlikte ele alan dürüst tarihsel analiz","Tamamen kötümser muhalif","Yabancı müdahaleyi öne çıkaran"]', 1, 'Demokratikleşme sürecini inceleyen metinler hem ilerlemeyi hem de gerileyişleri dürüstçe aktaran analitik bir tutum sergiler.', 3, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'İkinci Dünya Savaşı ve Türkiye' LIMIT 1), 'detail', 'İkinci Dünya Savaşı boyunca Türkiye''nin temel dış politika tutumu ne olmuştur?', '["Almanya yanında savaşa katılmak","Müttefikler yanında aktif savaşmak","Tarafsızlık politikasını sürdürmek","Sovyetler Birliği ile ittifak kurmak"]', 2, 'Türkiye, savaş boyunca zorlu denge politikalarıyla tarafsızlığını korumayı başarmış; Almanya ile Müttefiklere eş zamanlı olarak hammadde ihraç etmiştir.', 3, 5),
((SELECT id FROM text_library WHERE title = 'İkinci Dünya Savaşı ve Türkiye' LIMIT 1), 'detail', 'Türkiye''nin İkinci Dünya Savaşı döneminde çıkardığı Varlık Vergisi hangi grubu orantısız biçimde etkilemiştir?', '["Büyük tarım işletmecileri","Rum, Ermeni ve Yahudi gibi gayrimüslim azınlıklar","Kamu görevlileri","Yabancı şirketler"]', 1, 'Varlık Vergisi uygulamasında gayrimüslim azınlıklara Müslüman vatandaşlara oranla çok daha yüksek vergi biçilmiş, bu durum ciddi tartışmalara yol açmıştır.', 3, 6),
((SELECT id FROM text_library WHERE title = 'İkinci Dünya Savaşı ve Türkiye' LIMIT 1), 'inference', 'Türkiye''nin savaş sonunda Müttefikler safına geçmesinin zamanlaması ne tür bir dış politika hesabını yansıtır?', '["İdeolojik bağlılık","Savaşın sonucuna bakarak çıkarını en iyi biçimde güvence altına almaya yönelik pragmatik denge politikası","Tek taraflı bağlılık","Rusya korkusunun boyun eğdirmesi"]', 1, 'Türkiye, Almanya''nın yenilgisi kesinleşmeden harekete geçmeyerek BM kurucu üyesi olma ve olası tehditlerden korunma hesabıyla 1945''te savaşa girmiştir.', 3, 7),
((SELECT id FROM text_library WHERE title = 'İkinci Dünya Savaşı ve Türkiye' LIMIT 1), 'vocabulary', '"Tarafsızlık" dış politika bağlamında ne anlama gelir?', '["Uluslararası örgütlere üye olmamak","Silahlı çatışmalarda hiçbir tarafa katılmama politikası","Tüm komşularla çatışma içinde olmak","Yabancı yatırımlara kapalı olmak"]', 1, 'Tarafsızlık, bir devletin silahlı çatışmalarda aktif taraf olmama ve savaşan güçlerden eşit mesafede durma politikasıdır.', 3, 8),
((SELECT id FROM text_library WHERE title = 'İkinci Dünya Savaşı ve Türkiye' LIMIT 1), 'tone', 'Metin Türkiye''nin İkinci Dünya Savaşı''ndaki tutumunu nasıl değerlendirir?', '["Tamamen öven","Tamamen eleştiren","Diplomatik hesapları ve kısıtlamaları da göz önünde bulunduran dengeli tarihsel analiz","Yalnızca Varlık Vergisi''ni öne çıkaran"]', 2, 'İyi tarih yazımı, olayları o dönemin koşulları ve Türkiye''nin içinde bulunduğu kısıtlar çerçevesinde dengeli biçimde değerlendirir.', 3, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Millî Mücadele Dönemi ve Kurtuluş Savaşı' LIMIT 1), 'detail', 'Sakarya Meydan Muharebesi Millî Mücadele sürecinde hangi açıdan belirleyici olmuştur?', '["Yunan güçlerinin son saldırısını durdurarak stratejik üstünlüğü Türk kuvvetlerine kazandırmıştır","Barış görüşmelerini başlatmıştır","İstanbul''un işgaline neden olmuştur","İngiliz kuvvetlerini Anadolu''dan çıkarmıştır"]', 0, 'Ağustos-Eylül 1921''deki Sakarya Muharebesi, Yunan ilerleyişini durduran ve savaşın kaderini Türk kuvvetleri lehine çeviren dönüm noktasıdır.', 3, 5),
((SELECT id FROM text_library WHERE title = 'Millî Mücadele Dönemi ve Kurtuluş Savaşı' LIMIT 1), 'detail', 'Lozan Antlaşması''nın Türkiye açısından önemi nedir?', '["Osmanlı İmparatorluğu''nu yeniden kurmuştur","Türk egemenliğini ve yeni Türk devletinin sınırlarını uluslararası alanda tanımlamıştır","Türkiye''yi İkinci Dünya Savaşı''na sokmuştur","Kapitülasyonları yeniden düzenlemiştir"]', 1, 'Lozan (1923), Türkiye''nin Kurtuluş Savaşı zaferiyle elde ettiği yeni sınırları ve egemenliği tescil eden uluslararası barış antlaşmasıdır.', 3, 6),
((SELECT id FROM text_library WHERE title = 'Millî Mücadele Dönemi ve Kurtuluş Savaşı' LIMIT 1), 'inference', 'Mustafa Kemal''in Ankara''yı millî direniş merkezi olarak seçmesi nasıl bir stratejik değerlendirmeyi yansıtır?', '["İstanbul''un coğrafi olarak elverişsizliği","Ankara''nın işgal güçlerinden uzak iç kesimlerde olması ve gerektiğinde savunulabilir niteliği","Ankara''nın büyük bir liman şehri olması","Osmanlı sarayının Ankara''da bulunması"]', 1, 'İşgal altındaki İstanbul yerine iç bölgedeki Ankara, millî hareketin bağımsızca örgütlenip yönetilebileceği güvenli bir üs olarak tercih edilmiştir.', 3, 7),
((SELECT id FROM text_library WHERE title = 'Millî Mücadele Dönemi ve Kurtuluş Savaşı' LIMIT 1), 'vocabulary', '"Misak-ı Millî" kavramı ne anlama gelir?', '["Osmanlı borçlarını ödeme belgesi","Türk milletinin bütünlük ve bağımsızlık taleplerini ortaya koyan ulusal ant","Lozan''da imzalanan barış antlaşması","Kurtuluş Savaşı''nın askeri stratejisi"]', 1, 'Misak-ı Millî, Ocak 1920''de Meclis-i Mebusan tarafından kabul edilen ve Türk halkının vazgeçilemez toprak bütünlüğünü ilan eden belgedir.', 3, 8),
((SELECT id FROM text_library WHERE title = 'Millî Mücadele Dönemi ve Kurtuluş Savaşı' LIMIT 1), 'tone', 'Metin Millî Mücadele''yi nasıl ele alır?', '["Yabancı güçleri öven","Millî direnişi ve zaferi ön plana çıkaran coşkulu tarihsel anlatı","Savaş kayıplarını eleştiren","Tamamen askeri teknik analizden ibaret"]', 1, 'Kurtuluş Savaşı anlatıları genellikle millî birlik ve direnişi vurgulayan coşkulu bir tarihsel perspektif taşır.', 3, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Osmanlı Millet Sistemi' LIMIT 1), 'detail', 'Osmanlı millet sisteminde "millet" kavramı nasıl tanımlanıyordu?', '["Etnik köken temelinde ayrışan gruplar","Dini kimlik temelinde kendi iç işlerini özerk biçimde yürüten topluluklar","Dil birliğiyle tanımlanan halklar","Coğrafi bölgeye göre belirlenen idari birimler"]', 1, 'Osmanlı millet sistemi, topluluklarını dini kimlik üzerinden tanımlıyor; Rum Ortodoks, Ermeni, Yahudi gibi grupların kendi iç işlerini yönetmesine olanak tanıyordu.', 3, 5),
((SELECT id FROM text_library WHERE title = 'Osmanlı Millet Sistemi' LIMIT 1), 'detail', 'Millet sisteminin Osmanlı yönetimi için sağladığı pratik avantaj nedir?', '["Vergi toplama kolaylığı","Çok dinli ve çok kültürlü nüfusu tek merkezi yapı altında yönetme kapasitesi","Orduyu güçlendirme","Sınırları genişletme"]', 1, 'Millet sistemi, merkezin doğrudan müdahalesi olmaksızın dinî cemaatlere iç özerklik tanıyarak imparatorluğun büyük çeşitliliğini yönetilebilir kılıyordu.', 3, 6),
((SELECT id FROM text_library WHERE title = 'Osmanlı Millet Sistemi' LIMIT 1), 'inference', '19. yüzyılda Osmanlı''da milliyetçi hareketlerin yükselmesi millet sistemini nasıl zorlamıştır?', '["Millet sistemi milliyetçiliği tamamen engellemiştir","Etnik milliyetçilik, dini kimlik temelli birlikteliği aşındırarak ayrılıkçı taleplere zemin hazırlamıştır","Milliyetçilik millet sistemini güçlendirmiştir","Milliyetçilik yalnızca Müslüman toplulukları etkilemiştir"]', 1, 'Fransız Devrimi''nin yaydığı etnik milliyetçilik akımı, Osmanlı millet sisteminin dini temelli çerçevesini aşan ayrılıkçı hareketlere zemin hazırlamıştır.', 3, 7),
((SELECT id FROM text_library WHERE title = 'Osmanlı Millet Sistemi' LIMIT 1), 'vocabulary', '"Özerklik" kavramı Osmanlı millet sistemi bağlamında ne anlama gelir?', '["Tam bağımsızlık ve ayrı devlet","Belirli alanlarda kendi kendini yönetme hakkı tanınmış olmak","Merkezi yönetimden kopuş","Ordu kurma hakkı"]', 1, 'Millet sistemindeki özerklik; eğitim, dini ibadet ve aile hukukunu kapsayan, ancak tam bağımsızlık anlamına gelmeyen sınırlı öz yönetimdi.', 3, 8),
((SELECT id FROM text_library WHERE title = 'Osmanlı Millet Sistemi' LIMIT 1), 'tone', 'Yazar Osmanlı millet sistemini nasıl değerlendirir?', '["Tamamen başarısız bulan","Hem avantajlarını hem de sınırlılıklarını tarihsel bağlamda değerlendiren","Dönemine göre mükemmel bulan","Yalnızca azınlıkların bakış açısından ele alan"]', 1, 'Tarihsel analiz, kurumları bağlamı içinde hem güçlü hem de zayıf yönleriyle değerlendirmeyi gerektirir.', 3, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Atatürk''ün Eğitim Reformları' LIMIT 1), 'detail', '1924''te medreselerin kapatılması ve tevhid-i tedrisat kanununun çıkarılması hangi amacı taşıyordu?', '["Yabancı okulları kapatmak","Eğitimi tek çatı altında laikleştirerek modern ulusal müfredata kavuşturmak","Dini eğitimi tamamen yasaklamak","Özel okulları devletleştirmek"]', 1, 'Tevhid-i tedrisat, eğitimi tek bir laik çerçevede birleştirerek medrese ile modern okul ikiliğini sona erdirmiştir.', 3, 5),
((SELECT id FROM text_library WHERE title = 'Atatürk''ün Eğitim Reformları' LIMIT 1), 'detail', '1928''de gerçekleştirilen harf devriminin eğitim sistemine katkısı nedir?', '["Okuma-yazma oranını kısa vadede geçici olarak düşürmüştür","Latin alfabesiyle okuryazarlığı yaygınlaştırmayı kolaylaştırmış ve Batı kaynaklarına erişimi artırmıştır","Arapçayı zorunlu ders olarak eklemiştir","Yalnızca edebiyat eğitimini etkilemiştir"]', 1, 'Latin harfleri hem öğrenmeyi kolaylaştırmış hem de genç Cumhuriyet''in Batı bilim ve kültürüyle bütünleşmesine zemin hazırlamıştır.', 3, 6),
((SELECT id FROM text_library WHERE title = 'Atatürk''ün Eğitim Reformları' LIMIT 1), 'inference', 'Halk evleri ve köy enstitülerinin kurulması hangi eğitim felsefesini yansıtmaktadır?', '["Eğitimi yalnızca seçkin kesime yönelik tutmak","Eğitimi toplumun tüm kesimlerine taşıma ve kültürel dönüşümü tabana yayma amacı","Yabancı eğitim modellerini olduğu gibi kopyalamak","Askeri eğitimi sivil alana genişletmek"]', 1, 'Halk evleri ve köy enstitüleri, Cumhuriyet''in aydınlanma idealini şehirlerden taşraya ve köylere ulaştırarak kitlesel bir eğitim seferberliği başlatmıştır.', 3, 7),
((SELECT id FROM text_library WHERE title = 'Atatürk''ün Eğitim Reformları' LIMIT 1), 'vocabulary', '"Laiklik" eğitim bağlamında ne anlama gelir?', '["Dini derslerin zorunlu tutulması","Eğitimin dini kurumların denetiminden arındırılarak devlet kontrolüne alınması","Tüm dinlerin eğitimde eşit temsili","Özel dini okulların desteklenmesi"]', 1, 'Laik eğitim, müfredatın ve okulların dini otorite yerine sivil devlet tarafından düzenlenmesi anlamına gelir.', 3, 8),
((SELECT id FROM text_library WHERE title = 'Atatürk''ün Eğitim Reformları' LIMIT 1), 'tone', 'Metin Atatürk''ün eğitim reformlarını nasıl ele alır?', '["Reformlara tamamen karşı olan","Reformların hedeflerini ve Türkiye''nin dönüşümüne katkısını ön plana çıkaran","Reformları yalnızca teknik boyutuyla ele alan","Uluslararası karşılaştırma yaparak küçümseyen"]', 1, 'Atatürk reformlarını ele alan metinler genellikle modernleşme hedeflerini ve toplumsal dönüşüm üzerindeki etkilerini vurgulayan bir perspektif taşır.', 3, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Besinlerin Sindirimi ve Emilimi' LIMIT 1), 'detail', 'İnce bağırsakta besin emilimini artıran yapılar hangileridir?', '["Mide pilileri","Villüsler ve mikrovillüsler","Karaciğer kanalları","Safra kesesi"]', 1, 'İnce bağırsağın iç yüzeyindeki villüsler ve onların üzerindeki mikrovillüsler emilim yüzey alanını büyük ölçüde artırır.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Besinlerin Sindirimi ve Emilimi' LIMIT 1), 'detail', 'Karbonhidratların sindiriminde rol oynayan enzim hangisidir?', '["Pepsin","Lipaz","Amilaz","Tripsin"]', 2, 'Amilaz (tükürükte pityalin, pankreasta pankreatik amilaz) nişastayı maltoza parçalar.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Besinlerin Sindirimi ve Emilimi' LIMIT 1), 'inference', 'Safra tuzları yeterince üretilemezse yağların sindiriminde ne gibi bir sorun oluşur?', '["Yağlar daha hızlı sindirilir","Yağ emülsifikasyonu bozularak lipazın etki alanı daralır ve yağ sindirimi yavaşlar","Karbonhidrat sindirimi durur","Protein emilimi artar"]', 1, 'Safra tuzları yağları küçük damlaciyklara ayırarak lipazın yüzey alanını artırır; bunlar olmadan yağ sindirimi verimsizleşir.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Besinlerin Sindirimi ve Emilimi' LIMIT 1), 'vocabulary', '"Enzim" kavramı biyoloji bağlamında nasıl tanımlanır?', '["Sindirimi başlatan mekanik hareketler","Kimyasal tepkimeleri hızlandıran biyolojik katalizörler","Hücreye enerji sağlayan besinler","Bağırsak kaslarının kasılması"]', 1, 'Enzimler, biyolojik reaksiyonların aktivasyon enerjisini düşürerek hızını artıran protein yapılı katalizörlerdir.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Besinlerin Sindirimi ve Emilimi' LIMIT 1), 'tone', 'Metnin sindirim sistemini ele alış biçimi nasıl tanımlanabilir?', '["Edebi ve mecazlı","Açıklayıcı ve öğretici bilim dili","Karmaşık ve anlaşılması güç teknik","Kişisel deneyime dayanan"]', 1, 'Fen bilimleri ders metinleri, kavramları açık ve öğretici bir dille aktarır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Ekosistem ve Biyoçeşitlilik' LIMIT 1), 'detail', 'Bir ekosistemdeki besin zincirinin temelini oluşturan canlılar hangileridir?', '["Birincil tüketiciler","Üreticiler (ototroplar)","İkincil tüketiciler","Ayrıştırıcılar"]', 1, 'Fotosentez yapan bitkiler ve diğer ototroplar güneş enerjisini organik maddeye dönüştürerek besin zincirinin temelini oluşturur.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Ekosistem ve Biyoçeşitlilik' LIMIT 1), 'detail', 'Biyoçeşitlilik kaybının ekosistemler üzerindeki en önemli etkisi nedir?', '["Ekosistemi daha güçlü yapar","Ekosistemin işlevselliğini ve değişikliklere karşı direncini zayıflatır","Yeni türlerin ortaya çıkmasını hızlandırır","Besin zincirinin kısalmasını sağlar"]', 1, 'Çeşitlilik, ekosistemlere işlevsel yedeklilik kazandırır; tür kaybı besin ağlarını ve enerji akışını bozar.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Ekosistem ve Biyoçeşitlilik' LIMIT 1), 'inference', 'Bir habitattaki en tepedeki yırtıcı türün yok olması ekosisteme nasıl yansır?', '["Hiçbir değişiklik olmaz","Av türleri kontrolsüz çoğalarak bitki örtüsünü tahrip edebilir","Bitkiler daha hızlı büyür","Su kaynakları artar"]', 1, 'Tepe yırtıcıları av popülasyonlarını dengede tutar; bunların yokluğunda trofik basamak düzensizliği (trophic cascade) ortaya çıkar.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Ekosistem ve Biyoçeşitlilik' LIMIT 1), 'vocabulary', '"Habitat" kavramı ne anlama gelir?', '["Bir türün beslenmesi","Bir organizmanın doğal olarak yaşadığı ve ihtiyaçlarını karşıladığı ortam","Ekosistemdeki besin miktarı","Canlı türlerinin toplamı"]', 1, 'Habitat, bir türün barınma, beslenme ve üreme gereksinimlerini karşıladığı özgül yaşam ortamıdır.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Ekosistem ve Biyoçeşitlilik' LIMIT 1), 'tone', 'Metnin biyoçeşitlilik kaybına yaklaşımı nasıl tanımlanabilir?', '["Umursamaz ve tarafsız","Kaygı verici bularak koruma önemine dikkat çeken","Türlerin yok olmasını doğal bulan","Bilimsel değil duygusal"]', 1, 'Biyoçeşitlilik metinleri ekosistem hizmetlerinin ve türlerin korunmasının önemini vurgulayan kaygılı bir tutum taşır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Elektrik ve Manyetizma' LIMIT 1), 'detail', 'Elektrik akımı nasıl oluşur?', '["Protonların iletkende hareketiyle","Elektronların bir iletkende belirli bir yönde akmasıyla","Nötronların birbirine çarpmasıyla","Atomların parçalanmasıyla"]', 1, 'Elektrik akımı, serbest elektronların iletken boyunca yüksek potansiyelden düşük potansiyele doğru akmasıyla oluşur.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Elektrik ve Manyetizma' LIMIT 1), 'detail', 'Ohm yasasına göre direnci sabit bir iletkende gerilim artarsa akım nasıl değişir?', '["Azalır","Sabit kalır","Artar","Sıfıra düşer"]', 2, 'I = V/R formülüne göre R sabitken V artarsa I de orantılı olarak artar.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Elektrik ve Manyetizma' LIMIT 1), 'inference', 'Mıknatısın kuzey ve güney kutupları arasındaki çekme kuvveti, aynı kutuplar arasındaki itme kuvvetiyle karşılaştırıldığında ne söylenebilir?', '["Her ikisi de eşit","Çekme daima daha güçlüdür","Aynı fiziksel yasanın farklı yönlerdeki tezahürleridir","İtme kuvveti daima daha büyüktür"]', 2, 'Manyetik kutuplar arasındaki kuvvet aynı manyetik alan yasasından kaynaklanır; yön (çekme/itme) kutup benzerliğine bağlıdır.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Elektrik ve Manyetizma' LIMIT 1), 'vocabulary', '"Elektromanyetik indüksiyon" ne anlama gelir?', '["Pilde kimyasal enerjiyi elektriğe dönüştürmek","Değişen manyetik alan içindeki bir iletkende elektrik akımı oluşması","Elektrik yüküyle manyetik alanı birleştirmek","İki mıknatısı birbirine yapıştırmak"]', 1, 'Faraday yasasına göre değişen manyetik akı, iletkende elektromotor kuvvet ve dolayısıyla akım oluşturur.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Elektrik ve Manyetizma' LIMIT 1), 'tone', 'Metin elektrik ve manyetizma konularını nasıl aktarır?', '["Soyut ve anlaşılması güç","Günlük hayat örnekleriyle desteklenen açıklayıcı","Tarihsel kronoloji ağırlıklı","Felsefi ve spekülatif"]', 1, 'Fizik ders metinleri kavramları somut örneklerle destekleyerek öğrenciye anlamlı biçimde aktarır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Hücrenin Yapısı ve Organelleri' LIMIT 1), 'detail', 'Mitokondri hücrede hangi temel işlevi yerine getirir?', '["Protein sentezi","Hücresel solunum yoluyla ATP üretimi","DNA replikasyonu","Hücre bölünmesi"]', 1, 'Mitokondri, aerobik solunum aracılığıyla glukozdan ATP (enerji para birimi) üreterek hücrenin enerji merkezini oluşturur.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Hücrenin Yapısı ve Organelleri' LIMIT 1), 'detail', 'Bitki hücrelerini hayvan hücrelerinden ayıran yapılar nelerdir?', '["Ribozom ve mitokondri","Hücre duvarı, kloroplast ve büyük koful","Çekirdek ve hücre zarı","Lizozom ve Golgi aygıtı"]', 1, 'Bitki hücrelerine özgü yapılar; selülozdan oluşan hücre duvarı, fotosentez yapan kloroplastlar ve büyük merkezi kofultur.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Hücrenin Yapısı ve Organelleri' LIMIT 1), 'inference', 'Ribozomsuz bir hücre vücutta ne gibi bir soruna yol açar?', '["Enerji üretimi durur","Protein sentezi gerçekleşemez ve hücresel işlevler çöker","DNA kopyalanamaz","Hücre bölünmesi hızlanır"]', 1, 'Proteinler enzimlerin, yapı elemanlarının ve sinyallerin temelini oluşturur; ribozom olmadan protein üretimi durur.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Hücrenin Yapısı ve Organelleri' LIMIT 1), 'vocabulary', '"Osmoz" kavramı hücre biyolojisi bağlamında ne anlama gelir?', '["Hücrenin besin alması","Suyun yarı geçirgen zardan çözünmüş madde konsantrasyonunun düşük olduğu ortamdan yüksek olduğu ortama difüzyonu","Proteinlerin hücre dışına atılması","Hücre zarının eriyip çözülmesi"]', 1, 'Osmoz, suyun seçici geçirgen zardan daha az yoğun ortamdan daha yoğun ortama enerjisiz geçişidir.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Hücrenin Yapısı ve Organelleri' LIMIT 1), 'tone', 'Metin hücre yapısını öğrencilere nasıl aktarır?', '["Karmaşık ve teknik jargon dolu","Aşamalı ve görsel örneklerle desteklenen açıklayıcı","Yalnızca teorik ve soyut","Edebi ve mecaz ağırlıklı"]', 1, 'Biyoloji ders metinleri kavramları basitten karmaşığa giderek ve somut örneklerle açıklar.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Işığın Kırılması ve Optik Olaylar' LIMIT 1), 'detail', 'Işığın kırılması ne zaman gerçekleşir?', '["Işık tek ortamda ilerlerken","Işık farklı yoğunluktaki iki ortam arasındaki sınırı geçerken","Işık bir aynaya çarptığında","Işık tamamen soğurulduğunda"]', 1, 'Kırılma, ışığın hızının değiştiği farklı ortam sınırlarından geçerken yön değiştirmesi olayıdır.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Işığın Kırılması ve Optik Olaylar' LIMIT 1), 'detail', 'Bir prizma beyaz ışığı renklere ayırır; bu olayın nedeni nedir?', '["Prizma beyaz ışığı boyar","Farklı renklerin (dalga boylarının) prizmada farklı hızlarda ilerlemesi ve farklı açılarda kırılması","Prizma ışığı yansıtır","Prizma kırmızı ışığı soğurur"]', 1, 'Dispersiyon (yayınım), beyaz ışığın bileşen renklerinin farklı kırılma indislerine sahip olması nedeniyle prizmada ayrışmasıdır.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Işığın Kırılması ve Optik Olaylar' LIMIT 1), 'inference', 'Havadan suya geçen ışığın hızı azalır; bu bilgiden Snell yasası kullanılarak ne çıkarılabilir?', '["Işık yüzeyde tamamen yansır","Kırılma açısı gelme açısından küçük olur; ışın normale yaklaşır","Işık renk değiştirir","Kırılma açısı gelme açısından büyük olur"]', 1, 'Snell yasasına göre yavaşlayan ortamda ışık normale yaklaşır; n₁sinθ₁ = n₂sinθ₂ bağıntısı bunu matematiksel olarak gösterir.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Işığın Kırılması ve Optik Olaylar' LIMIT 1), 'vocabulary', '"Kırılma indisi" ne anlama gelir?', '["Bir yüzeyin parlaklık derecesi","Işığın boşluktaki hızının o ortamdaki hızına oranı","Işığın yansıma açısı","Lensin odak uzaklığı"]', 1, 'Kırılma indisi (n = c/v), bir maddenin ışığı ne ölçüde yavaşlattığını gösteren boyutsuz bir sayıdır.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Işığın Kırılması ve Optik Olaylar' LIMIT 1), 'tone', 'Metin optik olayları nasıl bir dille açıklar?', '["Ezberci ve salt formül odaklı","Günlük gözlem örnekleriyle desteklenen anlaşılır","Yalnızca tarihsel buluşları anlatan","İleri düzey matematikten bağımsız olmayan uzman dilli"]', 1, 'İyi bir fizik metni, soyut kavramları günlük hayattan örneklerle somutlaştırarak öğrenmeyi kolaylaştırır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Technology in Our Daily Lives' LIMIT 1), 'detail', 'Which technology has most significantly reduced the cost of accessing information in everyday life?', '["Television","The Internet and smartphones","Printing press","Radio"]', 1, 'The internet and smartphones have democratized access to vast amounts of information, making it available at minimal cost to billions of people.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Technology in Our Daily Lives' LIMIT 1), 'detail', 'What is the primary function of GPS technology in daily life?', '["Making phone calls","Providing precise location and navigation data","Storing personal files","Connecting to social media"]', 1, 'GPS (Global Positioning System) uses satellite signals to determine a device''s exact location, enabling navigation and location-based services.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Technology in Our Daily Lives' LIMIT 1), 'inference', 'If wearable health technology becomes more accurate and widely adopted, what is the most likely societal impact?', '["Healthcare costs will automatically disappear","Preventive care will become more common, potentially reducing late-stage disease diagnosis","Doctors will become unnecessary","People will stop exercising"]', 1, 'Continuous health monitoring enables earlier detection of problems, shifting healthcare toward prevention rather than treatment.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Technology in Our Daily Lives' LIMIT 1), 'vocabulary', 'In the context of technology, what does "cloud computing" mean?', '["Storing data on physical hard drives at home","Accessing computing resources and storage over the internet on remote servers","Using solar-powered computers","A type of weather prediction software"]', 1, 'Cloud computing delivers computing services including storage, processing, and software over the internet rather than on local hardware.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Technology in Our Daily Lives' LIMIT 1), 'tone', 'How would you describe the tone of the text regarding technology''s role in daily life?', '["Fearful and technophobic","Balanced and informative, acknowledging both benefits and concerns","Exclusively promotional","Indifferent and detached"]', 1, 'The text presents technological developments in an informative manner while acknowledging both their benefits and potential challenges.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Denklemler ve Eşitsizlikler' LIMIT 1), 'detail', 'Bir denklemde her iki tarafı aynı sayıyla çarpmak sonucu nasıl etkiler?', '["Denklemi geçersiz kılar","Denklemin çözümünü değiştirmez","Her zaman yeni bir çözüm üretir","Yalnızca pozitif sayılarda geçerlidir"]', 1, 'Denklemin her iki tarafına aynı işlemi uygulamak eşitliği korur; bu denklem çözümünün temel ilkesidir.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Denklemler ve Eşitsizlikler' LIMIT 1), 'detail', 'Eşitsizliğin her iki tarafı negatif bir sayıyla çarpılırsa ne olur?', '["Eşitsizlik işareti değişmez","Eşitsizlik işareti tersine döner","Eşitsizlik sıfıra eşitlenir","Eşitsizlik geçersiz hâle gelir"]', 1, 'Her iki tarafı negatif sayıyla çarpmak büyük-küçük ilişkisini tersine çevirir; bu nedenle eşitsizlik işareti de değişmelidir.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Denklemler ve Eşitsizlikler' LIMIT 1), 'inference', '2x + 5 = 13 denkleminin çözümü x = 4''tür. Bu bilgiden 2x + 5 > 13 eşitsizliğinin çözüm kümesi hakkında ne söylenebilir?', '["x < 4","x = 4","x > 4","x ≤ 4"]', 2, 'Eşitliğin sağlandığı değerin ötesinde sol taraf sağ tarafı aşar; dolayısıyla x > 4 için 2x+5 > 13 sağlanır.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Denklemler ve Eşitsizlikler' LIMIT 1), 'vocabulary', '"Doğrusal denklem" kavramı ne anlama gelir?', '["Değişkenlerin karesi alınan denklemler","Değişkenlerin yalnızca birinci kuvvetiyle oluşturulan denklemler","Birden fazla çözümü olan denklemler","Yalnızca tam sayı çözümlü denklemler"]', 1, 'Doğrusal denklemlerde değişkenler yalnızca birinci dereceden görünür; grafikleri düz bir çizgidir.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Denklemler ve Eşitsizlikler' LIMIT 1), 'tone', 'Metin denklem ve eşitsizlikleri öğrencilere nasıl aktarır?', '["Yalnızca sonuçları ezberletmeye yönelik","Adım adım mantıksal akıl yürütmeyi ön plana çıkaran öğretici","Tarihsel anekdotlarla süslenmiş","Soyut ve örnek içermeyen"]', 1, 'İyi matematik metinleri öğrencilerin süreç mantığını kavramasını hedefleyen açıklayıcı bir yapıya sahiptir.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Olasılık ve İstatistik' LIMIT 1), 'detail', 'Bir olayın olasılığı nasıl hesaplanır?', '["Deneyin kaçıncı kez tekrarlandığıyla","İstenen sonuç sayısının toplam eşit olası sonuç sayısına bölünmesiyle","Yalnızca geçmiş verilere dayalı tahminle","Olayın gerçekleşme süresinin ölçülmesiyle"]', 1, 'Klasik olasılıkta P(A) = uygun sonuç sayısı / toplam eşit olasılıklı sonuç sayısı formülü kullanılır.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Olasılık ve İstatistik' LIMIT 1), 'detail', 'Ortalama ile medyan arasındaki temel fark nedir?', '["İkisi her zaman eşittir","Ortalama tüm değerleri kullanırken medyan ortadaki değeri verir; aykırı değerlerden etkilenme düzeyleri farklıdır","Medyan yalnızca küçük veri setlerinde kullanılır","Ortalama daima medyandan büyüktür"]', 1, 'Aykırı değerler ortalamayı çarpıtır; medyan sıralı listenin ortasındaki değerdir ve aykırı değerlerden daha az etkilenir.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Olasılık ve İstatistik' LIMIT 1), 'inference', 'Bir sınıfın not ortalaması 70 iken medyanı 65 ise bu veri seti hakkında ne söylenebilir?', '["Veriler simetriktir","Yüksek notlar nedeniyle sağa çarpık bir dağılım vardır","Tüm notlar 65 ile 70 arasındadır","Veri setinde hata vardır"]', 1, 'Ortalamanın medyandan büyük olması, yüksek değerlerin (yüksek notların) ortalamayı yukarı çektiğine işaret eder; bu da sağa çarpık dağılımdır.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Olasılık ve İstatistik' LIMIT 1), 'vocabulary', '"Örneklem" kavramı istatistikte ne anlama gelir?', '["İncelenen tüm bireyler","Anakütlenin tamamını temsil etmesi amacıyla seçilen küçük alt grup","Veri setindeki en sık tekrar eden değer","Araştırmanın amacı"]', 1, 'Örneklem, anakütleden alınan ve onu temsil etmesi beklenen alt kümedir; anakütlenin tamamına ulaşmak çoğu zaman mümkün değildir.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Olasılık ve İstatistik' LIMIT 1), 'tone', 'Metin olasılık ve istatistik konularını nasıl ele alır?', '["Soyut formüller yığını olarak","Günlük karar örnekleriyle ilişkilendiren pratik ve açıklayıcı","Yalnızca akademik araştırma bağlamında","Tarihsel gelişimini kronolojik sırayla anlatan"]', 1, 'İyi matematik metinleri soyut kavramları gerçek hayat bağlamlarıyla ilişkilendirerek somutlaştırır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Coğrafi Bölgeleri' LIMIT 1), 'detail', 'Karadeniz Bölgesi''nin tarıma olan etkisi bakımından en belirgin özelliği nedir?', '["Kurak iklim nedeniyle tarıma elverişsiz olması","Bol yağış ve nemli iklim sayesinde çay ve fındık yetiştiriciliğine uygunluğu","Yüksek tarım platolarına sahip olması","Sulama sistemlerine en fazla ihtiyaç duyulan bölge olması"]', 1, 'Karadeniz''in nemli ve yağışlı iklimi, başta Rize ve Trabzon olmak üzere bölgenin çay ve fındık üretiminin dünya lideri olmasını sağlamıştır.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Coğrafi Bölgeleri' LIMIT 1), 'detail', 'İç Anadolu Bölgesi''nin iklim ve tarım açısından en belirgin özelliği nedir?', '["Bol yağış ve orman örtüsü","Yarı kurak iklim ve tahıl tarımına elverişli geniş ovalar","Akdeniz ikliminin egemenliği","Yüksek dağ sıraları"]', 1, 'Konya Ovası başta olmak üzere İç Anadolu''nun geniş düzlükleri ve yarı kurak iklimi buğday ve arpa gibi tahılların yoğun yetiştirildiği bir ortam sunar.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Coğrafi Bölgeleri' LIMIT 1), 'inference', 'Marmara Bölgesi''nin hem tarım hem de sanayi açısından gelişmiş olması nasıl açıklanabilir?', '["Bölgenin en soğuk iklime sahip olması","Uygun iklim, verimli topraklar, İstanbul''un büyük pazarı ve ulaşım kolaylıklarının bir araya gelmesi","Petrol rezervleri","Yoğun göç alan tek bölge olması"]', 1, 'Marmara, ılıman iklimi, verimli tarım arazileri, kolay ulaşım ve büyük nüfus merkezleri sayesinde Türkiye''nin en çok yönlü ekonomik bölgesidir.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Coğrafi Bölgeleri' LIMIT 1), 'vocabulary', '"Yağış rejimi" kavramı ne anlama gelir?', '["Yıllık toplam yağış miktarı","Yağışların mevsimler ve aylar içindeki dağılım örüntüsü","Yağmurun düşme hızı","Nem oranının ölçümü"]', 1, 'Yağış rejimi, yağışların yıl içinde hangi mevsimlerde yoğunlaştığını ve nasıl dağıldığını gösterir; tarımsal planlama açısından kritik öneme sahiptir.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Coğrafi Bölgeleri' LIMIT 1), 'tone', 'Metnin Türkiye''nin coğrafi bölgelerini ele alış biçimi nasıl tanımlanabilir?', '["Eleştirel ve olumsuz","Tanımlayıcı, karşılaştırmalı ve bilgilendirici","Edebi ve öznel","Yalnızca turizm odaklı"]', 1, 'Coğrafya metinleri bölgelerin fiziksel, iklimsel ve ekonomik özelliklerini betimleyici ve karşılaştırmalı bir dille aktarır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Anadolu Medeniyetleri' LIMIT 1), 'detail', 'Hititlerin Anadolu medeniyetleri tarihindeki özgün katkısı nedir?', '["İlk yazı sistemini geliştirmeleri","Demir işlemeciliğini yaygınlaştırmaları ve güçlü bir hukuk sistemi kurmaları","Tekerleği icat etmeleri","İlk parayı basmaları"]', 1, 'Hititler demir metalurjisini geliştirerek Anadolu''ya yaydılar ve Hammurabi''yle eş dönemde gelişmiş bir hukuk sistemi oluşturdular.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Anadolu Medeniyetleri' LIMIT 1), 'detail', 'Çatalhöyük''ün dünya arkeoloji tarihi açısından önemi nedir?', '["Roma döneminin ilk şehridir","Dünyanın bilinen en eski büyük yerleşim alanlarından biri olup Neolitik kentleşme konusunda önemli ipuçları sunar","Bronz çağının en büyük saray kompleksini barındırır","İlk yazının bulunduğu kenttir"]', 1, 'MÖ 7500 - 5700 yılları arasına tarihlenen Çatalhöyük, erken kentleşme, dini ritüeller ve toplumsal örgütlenme hakkında değerli veriler sunar.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Anadolu Medeniyetleri' LIMIT 1), 'inference', 'Anadolu''nun çok sayıda medeniyete ev sahipliği yapması tarih boyunca hangi temel faktörle ilişkilendirilebilir?', '["Nüfusun her dönem çok az olması","Anadolu''nun kıtalar ve denizler arasındaki ticaret ve geçiş yolu konumu","Bol altın rezervleri","Anadolu''nun diğer bölgelerden tamamen izole olması"]', 1, 'Anadolu''nun Asya ile Avrupa arasındaki köprü konumu, medeniyetlerin bir araya gelmesini, ticaret yapmalarını ve birbirlerini etkilemesini kolaylaştırmıştır.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Anadolu Medeniyetleri' LIMIT 1), 'vocabulary', '"Arkeoloji" kavramı ne anlama gelir?', '["Antik dilleri inceleyen bilim dalı","Geçmiş insan topluluklarının kalıntılarını kazıp inceleyerek tarihi yeniden kurmaya çalışan bilim dalı","Antik metinleri çözümleyen bilim dalı","Coğrafi harita çizimi"]', 1, 'Arkeoloji, artefaktları ve yapıları sistemli biçimde kazarak insan geçmişini anlamamıza yardımcı olur.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Anadolu Medeniyetleri' LIMIT 1), 'tone', 'Yazar Anadolu medeniyetlerini anlatırken nasıl bir tutum sergiler?', '["Tek bir medeniyeti üstün gösteren","Anadolu''nun zengin kültürel katmanlarına hayranlık duyan keşifçi","Arkeolojik bulguları sorgulayan şüpheci","Tamamen kronolojik ve duygusuz"]', 1, 'Metin, Anadolu''nun medeniyetler beşiği olma özelliğini coşkuyla vurgulayan bir anlatı tonu taşır.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Osmanlı''nın Yükseliş Dönemi' LIMIT 1), 'detail', 'Osmanlı İmparatorluğu''nun yükseliş döneminde siyasi ve askeri gücünü besleyen temel unsurlardan biri nedir?', '["Yalnızca deniz ticareti","Merkezi otoriteyi güçlendiren devşirme sistemi ve kapıkulu ordusu","Rönesans kültüründen doğrudan esinlenen sanat","Avrupa''dan ithal edilen ateşli silahlar"]', 1, 'Devşirme sistemi ve kapıkulu ordusu, sultana sadık profesyonel bir asker ve yönetici sınıfı oluşturarak merkezi otoriteyi pekiştirmiştir.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Osmanlı''nın Yükseliş Dönemi' LIMIT 1), 'detail', '1453''te İstanbul''un fethi Osmanlı açısından hangi stratejik önemi taşıyordu?', '["Yalnızca dini sembolik önem","Ticaret yolları üzerinde tam kontrol ve imparatorluğun kalıcı başkentini kazanmak","İspanya''ya karşı ittifak kurmak","Anadolu topraklarını tamamlamak"]', 1, 'İstanbul''un fethi, Osmanlı''ya Boğazlar üzerinde denetim, köklü bir başkent ve imparatorluk meşruiyeti kazandırmıştır.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Osmanlı''nın Yükseliş Dönemi' LIMIT 1), 'inference', 'Yavuz Sultan Selim döneminde Hicaz ve Mısır''ın alınması Osmanlı''nın iç meşruiyeti açısından nasıl bir sonuç doğurmuştur?', '["Yalnızca ekonomik gelir artışı sağlamıştır","Kutsal topraklar ve halifeliğin Osmanlı''ya geçmesiyle dini otorite de kazanılmıştır","Anadolu''nun dini yapısını değiştirmiştir","Avrupa Hristiyan dünyasıyla iyi ilişkiler kurulmasına yardımcı olmuştur"]', 1, 'Haremeyn''in hizmetkârı unvanı ve halifeliğin Osmanlı''ya geçmesi, sultanlara Müslüman dünya genelinde din ve siyaset üzerinde güçlü bir meşruiyet zemini sağlamıştır.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Osmanlı''nın Yükseliş Dönemi' LIMIT 1), 'vocabulary', '"Tımar sistemi" ne anlama gelir?', '["Osmanlı vergi affı uygulaması","Savaş hizmetleri karşılığında askerlere geliri bırakılan toprak tahsisi","Osmanlı tarım reformu","Vakıf arazi yönetimi"]', 1, 'Tımar sistemi, sipahilere savaş hizmetleri karşılığında belirli bir arazinin vergilerini toplama hakkı tanıyan toprak-askerlik ilişkisi modeliydi.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Osmanlı''nın Yükseliş Dönemi' LIMIT 1), 'tone', 'Metnin Osmanlı yükseliş dönemini ele alış biçimi nasıl tanımlanabilir?', '["Tamamen övgü dolu milliyetçi","Tarihsel başarıları nesnel bağlamda aktaran analitik","Osmanlı''yı küçümseyen","Yalnızca askeri tarih odaklı"]', 1, 'Osmanlı tarihini ele alan metinler, imparatorluğun genişleme nedenlerini siyasi, ekonomik ve askeri açıdan analiz eden dengeli bir üslup benimser.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türkçede Sözcük Türleri' LIMIT 1), 'detail', 'Türkçede sıfatların temel işlevi nedir?', '["Eylemi nitelendirmek","İsimleri nitelendirmek veya belirli hâle getirmek","Cümleye bağlaç görevi görmek","Yüklem oluşturmak"]', 1, 'Sıfatlar, isimlerin önüne gelerek onların niteliğini, sırasını, miktarını veya gösterme özelliğini belirler.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Türkçede Sözcük Türleri' LIMIT 1), 'detail', 'Fiilimsi (eylemsi) nedir?', '["Yüklem görevindeki fiil","Fiilden türeyen ancak cümlede isim, sıfat veya zarf işlevi gören sözcük grubu","Yardımcı fiil","Fiil çekimi"]', 1, 'Fiilimsiler; isim-fiil, sıfat-fiil ve zarf-fiil olmak üzere üç türde görülür ve yüklem görevi dışındaki işlevleri üstlenir.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Türkçede Sözcük Türleri' LIMIT 1), 'inference', '"Güzel" sözcüğü "Güzel konuştu" cümlesinde hangi sözcük türüdür?', '["Sıfat","Zarf","İsim","Zamir"]', 1, '"Güzel" sözcüğü burada "konuştu" eylemini nitelendirdiğinden zarf (belirteç) görevindedir.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Türkçede Sözcük Türleri' LIMIT 1), 'vocabulary', '"Bağlaç" sözcük türü ne işe yarar?', '["İsimlerin yerine geçer","Sözcükleri, öbekleri veya cümleleri birbirine bağlar","Eylemlerin zamanını belirtir","İsimleri niteler"]', 1, 'Bağlaçlar (ve, ama, çünkü, ancak vb.) sözcük, öbek ya da cümleleri anlamsal ve sözdizimsel açıdan birleştiren işlev sözcükleridir.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Türkçede Sözcük Türleri' LIMIT 1), 'tone', 'Metnin dil bilgisi konusunu ele alış biçimi nasıl nitelendirilebilir?', '["Kural odaklı ve ezbere yönlendiren","Örneklerle desteklenen işlevsel ve açıklayıcı","Tamamen teorik ve uygulama içermeyen","Edebi metin analizine dayanan"]', 1, 'İyi bir dil bilgisi metni, kuralları somut örneklerle pekiştirerek öğrencilerin işlevsel dil farkındalığı kazanmasına yardımcı olur.', 2, 9);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Demokrasi ve Temel Haklar' LIMIT 1), 'detail', 'Doğrudan demokrasi ile temsili demokrasi arasındaki temel fark nedir?', '["İkisi aynı anlama gelir","Doğrudan demokraside vatandaşlar kararlara bizzat katılırken temsili demokraside seçilmiş temsilciler üzerinden katılım sağlanır","Temsili demokrasi yalnızca monarşilerde uygulanır","Doğrudan demokrasi daha az özgürlük sağlar"]', 1, 'Doğrudan demokrasi, başta Antik Yunan olmak üzere küçük topluluk kararlarında görülür; temsili demokrasi modern devletlerin temel yönetim biçimidir.', 2, 5),
((SELECT id FROM text_library WHERE title = 'Demokrasi ve Temel Haklar' LIMIT 1), 'detail', 'İnsan haklarının "evrensel" nitelik taşıması ne anlama gelir?', '["Yalnızca belirli ülkelerde geçerli olduğunu","Tüm insanların bu haklara ırk, cinsiyet veya uyruğa bakılmaksızın eşit biçimde sahip olduğunu","Yalnızca uluslararası hukuk kapsamında güvence altında olduğunu","Yalnızca yetişkinlere tanındığını"]', 1, 'İnsan hakları, bireyin salt insan olması nedeniyle doğuştan kazandığı, hiçbir ayrım gözetmeksizin herkese tanınan evrensel haklardır.', 2, 6),
((SELECT id FROM text_library WHERE title = 'Demokrasi ve Temel Haklar' LIMIT 1), 'inference', 'Seçim sisteminin adil olmadığı bir demokraside ne gibi bir sorun ortaya çıkar?', '["Ekonomi zarar görmez","Halkın iradesi gerçek anlamda yönetime yansıyamaz ve temsil meşruiyeti zayıflar","Yargı sistemi güçlenir","Sivil özgürlükler kendiliğinden artar"]', 1, 'Seçim sisteminin manipüle edildiği ya da adil olmadığı durumlarda demokratik katılımın meşruiyeti tartışmalı hâle gelir.', 2, 7),
((SELECT id FROM text_library WHERE title = 'Demokrasi ve Temel Haklar' LIMIT 1), 'vocabulary', '"Hukuk devleti" ilkesi ne anlama gelir?', '["Devletin istediği yasayı çıkarması","Devlet otoritesinin de yazılı kurallara ve anayasaya tabi olması","Yasaların yalnızca vatandaşlar için bağlayıcı olması","Yargı bağımsızlığının olmaması"]', 1, 'Hukuk devleti, devlet organlarının da hukukla bağlı olduğu ve kimsenin kanunun üstünde yer almadığı ilkesini ifade eder.', 2, 8),
((SELECT id FROM text_library WHERE title = 'Demokrasi ve Temel Haklar' LIMIT 1), 'tone', 'Metnin demokrasi ve haklar konusundaki tutumu nasıl tanımlanır?', '["Belirli bir siyasi partiyi destekleyen","Demokratik değerleri ve insan haklarını evrensel bir perspektifle savunan","Demokrasiye şüpheyle yaklaşan","Yalnızca seçim prosedürlerine odaklanan"]', 1, 'Demokrasi ve insan hakları metinleri genellikle bu değerlerin önemini ön plana çıkaran normatif bir perspektif taşır.', 2, 9);
